sparql:
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ( SUM( IF( ?currency = "EUR" , 1 , 0 ) ) AS ?eurCount ) ( SUM( IF( ?currency = "CZK" , 1 , 0 ) ) AS ?czkCount ) ( xsd:decimal ( SUM( IF( ?currency = "EUR" , 1 , 0 ) ) ) / xsd:decimal ( SUM( IF( ?currency = "CZK" , 1 , 0 ) ) ) AS ?ratio ) WHERE {
  ?s <http://debitcard.org/schema#currency> ?currency .
}

PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?customer ( SUM( ?val ) AS ?totalConsumption ) ?label WHERE {
  ?cons <http://debitcard.org/schema#consumptionValue> ?val ; <http://debitcard.org/schema#date> ?date ; <http://debitcard.org/schema#forCustomer> ?customer .
  ?customer <http://debitcard.org/schema#segment> "LAM" .
  OPTIONAL {
    ?customer rdfs:label ?label
  }
  FILTER ( xsd:integer ( ?date ) >= 201201 && xsd:integer ( ?date ) <= 201212 )
}
GROUP BY ?customer ?label
ORDER BY ?totalConsumption
LIMIT 1

PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ( AVG( xsd:decimal ( ?cons ) ) AS ?avgMonthlyConsumption ) WHERE {
  ?ym <http://debit_card_specializing.org/yearmonth#CustomerID> ?custID ; <http://debit_card_specializing.org/yearmonth#Date> ?date ; <http://debit_card_specializing.org/yearmonth#Consumption> ?cons .
  ?cust <http://debit_card_specializing.org/customers#CustomerID> ?custID ; <http://debit_card_specializing.org/customers#Segment> ?segment .
  FILTER ( ( datatype( ?date ) = xsd:integer && ?date >= 201301 && ?date <= 201312 ) || regex( str( ?date ) , "^2013" ) ) FILTER ( regex( lcase( str( ?segment ) ) , "sme" ) )
}

PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?sumCZK ?sumEUR ( ?sumCZK - ?sumEUR AS ?difference ) WHERE {
  {
    SELECT ( SUM( xsd:decimal ( ?amount ) ) AS ?sumCZK ) WHERE {
      ?tx <http://debit_card_specializing.org/transactions_1k#GasStationID> ?gas .
      ?tx <http://debit_card_specializing.org/transactions_1k#Time> ?time .
      FILTER ( STRSTARTS( STR( ?time ) , "2012" ) ) .
      ?tx <http://debit_card_specializing.org/transactions_1k#Amount> ?amount .
      ?tx <http://debit_card_specializing.org/transactions_1k#CustomerID> ?cust .
      ?cust <http://debit_card_specializing.org/customers#Currency> "CZK" .
    }
  }
  {
    SELECT ( SUM( xsd:decimal ( ?amount ) ) AS ?sumEUR ) WHERE {
      ?tx2 <http://debit_card_specializing.org/transactions_1k#GasStationID> ?gas2 .
      ?tx2 <http://debit_card_specializing.org/transactions_1k#Time> ?time2 .
      FILTER ( STRSTARTS( STR( ?time2 ) , "2012" ) ) .
      ?tx2 <http://debit_card_specializing.org/transactions_1k#Amount> ?amount .
      ?tx2 <http://debit_card_specializing.org/transactions_1k#CustomerID> ?cust2 .
      ?cust2 <http://debit_card_specializing.org/customers#Currency> "EUR" .
    }
  }
}

SELECT ?minSME ?minLAM ?minKAM ( ?minSME - ?minLAM AS ?SME_minus_LAM ) ( ?minLAM - ?minKAM AS ?LAM_minus_KAM ) ( ?minKAM - ?minSME AS ?KAM_minus_SME ) WHERE {
  {
    SELECT ( MIN( ?annual ) AS ?minSME ) WHERE {
      {
        SELECT ?cust ( SUM( ?val ) AS ?annual ) WHERE {
          ?cust <http://debitcard.org/schema#segment> "SME" .
          ?cust <http://debitcard.org/schema#currency> "CZK" .
          ?cons <http://debitcard.org/schema#forCustomer> ?cust ; <http://debitcard.org/schema#consumptionValue> ?val ; <http://debitcard.org/schema#date> ?date .
          FILTER ( STRSTARTS( STR( ?date ) , "2013" ) )
        }
        GROUP BY ?cust
      }
    }
  }
  {
    SELECT ( MIN( ?annual ) AS ?minLAM ) WHERE {
      {
        SELECT ?cust ( SUM( ?val ) AS ?annual ) WHERE {
          ?cust <http://debitcard.org/schema#segment> "LAM" .
          ?cust <http://debitcard.org/schema#currency> "CZK" .
          ?cons <http://debitcard.org/schema#forCustomer> ?cust ; <http://debitcard.org/schema#consumptionValue> ?val ; <http://debitcard.org/schema#date> ?date .
          FILTER ( STRSTARTS( STR( ?date ) , "2013" ) )
        }
        GROUP BY ?cust
      }
    }
  }
  {
    SELECT ( MIN( ?annual ) AS ?minKAM ) WHERE {
      {
        SELECT ?cust ( SUM( ?val ) AS ?annual ) WHERE {
          ?cust <http://debitcard.org/schema#segment> "KAM" .
          ?cust <http://debitcard.org/schema#currency> "CZK" .
          ?cons <http://debitcard.org/schema#forCustomer> ?cust ; <http://debitcard.org/schema#consumptionValue> ?val ; <http://debitcard.org/schema#date> ?date .
          FILTER ( STRSTARTS( STR( ?date ) , "2013" ) )
        }
        GROUP BY ?cust
      }
    }
  }
}

SELECT ?segment ( SUM( IF( STRSTARTS( STR( ?date ) , "2012" ) , ?cons , 0 ) ) AS ?cons2012 ) ( SUM( IF( STRSTARTS( STR( ?date ) , "2013" ) , ?cons , 0 ) ) AS ?cons2013 ) ( ( SUM( IF( STRSTARTS( STR( ?date ) , "2013" ) , ?cons , 0 ) ) - SUM( IF( STRSTARTS( STR( ?date ) , "2012" ) , ?cons , 0 ) ) ) / SUM( IF( STRSTARTS( STR( ?date ) , "2012" ) , ?cons , 0 ) ) * 100.0 AS ?pctIncrease ) WHERE {
  ?obs <http://debit_card_specializing.org/yearmonth#Consumption> ?cons .
  OPTIONAL {
    ?obs <http://debit_card_specializing.org/yearmonth#Date> ?date
  }
  .
  OPTIONAL {
    ?obs <http://debit_card_specializing.org/customers#Segment> ?segment
  }
  .
  OPTIONAL {
    ?obs ?link ?cust .
    FILTER ( STRSTARTS( STR( ?cust ) , "http://debit_card_specializing.org/customers/" ) ) ?cust <http://debit_card_specializing.org/customers#Segment> ?segment .
  }
  FILTER ( BOUND( ?segment ) && ( STR( ?segment ) = "SME" || STR( ?segment ) = "LAM" || STR( ?segment ) = "KAM" || STR( ?segment ) = "http://debit_card_specializing.org/customers#SME" || STR( ?segment ) = "http://debit_card_specializing.org/customers#LAM" || STR( ?segment ) = "http://debit_card_specializing.org/customers#KAM" ) )
}
GROUP BY ?segment
HAVING ( SUM( IF( STRSTARTS( STR( ?date ) , "2012" ) , ?cons , 0 ) ) > 0 )
ORDER BY DESC ( ?pctIncrease )

PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ( SUM( xsd:decimal ( ?cons ) ) AS ?totalConsumption ) ( <http://debit_card_specializing.org/customers/CustomerID=6> AS ?customer ) WHERE {
  ?ym <http://debit_card_specializing.org/yearmonth#CustomerID> ?cid ; <http://debit_card_specializing.org/yearmonth#Date> ?date ; <http://debit_card_specializing.org/yearmonth#Consumption> ?cons .
  FILTER ( str( ?cid ) = "6" || ?cid = "6" || ?cid = 6 || ?cid = <http://debit_card_specializing.org/customers/CustomerID=6> ) FILTER ( ?date >= "201308" && ?date <= "201311" )
}

SELECT ( ?czCount - ?skCount AS ?difference ) WHERE {
  {
    SELECT ( COUNT( ?gs ) AS ?czCount ) WHERE {
      ?gs <http://debit_card_specializing.org/gasstations#Segment> ?segment .
      FILTER ( CONTAINS( LCASE( str( ?segment ) ) , "discount" ) ) ?gs <http://debit_card_specializing.org/gasstations#Country> ?country .
      FILTER ( CONTAINS( LCASE( str( ?country ) ) , "czech" ) )
    }
  }
  {
    SELECT ( COUNT( ?gs2 ) AS ?skCount ) WHERE {
      ?gs2 <http://debit_card_specializing.org/gasstations#Segment> ?segment2 .
      FILTER ( CONTAINS( LCASE( str( ?segment2 ) ) , "discount" ) ) ?gs2 <http://debit_card_specializing.org/gasstations#Country> ?country2 .
      FILTER ( CONTAINS( LCASE( str( ?country2 ) ) , "slovak" ) || CONTAINS( LCASE( str( ?country2 ) ) , "slovakia" ) )
    }
  }
}

SELECT ?czkCount ?eurCount ( ?czkCount - ?eurCount AS ?difference ) WHERE {
  {
    SELECT ( COUNT( DISTINCT ?cust ) AS ?czkCount ) WHERE {
      ?cust <http://debitcard.org/schema#segment> ?seg .
      FILTER ( lcase( str( ?seg ) ) = "sme" ) .
      ?cust <http://debitcard.org/schema#currency> ?currency .
      FILTER ( lcase( str( ?currency ) ) = "czk" )
    }
  }
  {
    SELECT ( COUNT( DISTINCT ?cust ) AS ?eurCount ) WHERE {
      ?cust <http://debitcard.org/schema#segment> ?seg2 .
      FILTER ( lcase( str( ?seg2 ) ) = "sme" ) .
      ?cust <http://debitcard.org/schema#currency> ?currency2 .
      FILTER ( lcase( str( ?currency2 ) ) = "eur" )
    }
  }
}

SELECT ?total ?above ( ?above * 100.0 / ?total AS ?percent ) WHERE {
  {
    SELECT ( COUNT( DISTINCT ?cust ) AS ?total ) WHERE {
      ?cust <http://debitcard.org/schema#segment> "LAM" .
    }
  }
  {
    SELECT ( COUNT( DISTINCT ?cust2 ) AS ?above ) WHERE {
      ?cons <http://debitcard.org/schema#consumptionValue> ?val ; <http://debitcard.org/schema#forCustomer> ?cust2 .
      ?cust2 <http://debitcard.org/schema#segment> "LAM" .
      FILTER ( ?val > 46.73 )
    }
  }
}

SELECT ( COUNT( DISTINCT ?c ) AS ?totalCustomers ) ( COUNT( DISTINCT ?c_gt ) AS ?numGreater ) ( ( 100.0 * COUNT( DISTINCT ?c_gt ) ) / COUNT( DISTINCT ?c ) AS ?percentage ) WHERE {
  ?c a <http://debitcard.org/schema#Customer> .
  OPTIONAL {
    ?cons a <http://debitcard.org/schema#MonthlyConsumption> ; <http://debitcard.org/schema#date> "201202" ; <http://debitcard.org/schema#consumptionValue> ?val ; <http://debitcard.org/schema#forCustomer> ?c .
    FILTER ( ?val > 528.3 ) BIND( ?c AS ?c_gt )
  }
}

SELECT ?consumptionItem ?date ?consumptionValue WHERE {
  {
    SELECT ( MAX( ?v ) AS ?maxVal ) WHERE {
      ?it <http://debitcard.org/schema#date> ?d2 ; <http://debitcard.org/schema#consumptionValue> ?v .
      FILTER ( STRSTARTS( STR( ?d2 ) , "2012" ) )
    }
  }
  ?consumptionItem <http://debitcard.org/schema#date> ?date ; <http://debitcard.org/schema#consumptionValue> ?consumptionValue .
  FILTER ( STRSTARTS( STR( ?date ) , "2012" ) ) FILTER ( ?consumptionValue = ?maxVal )
}

SELECT ?d WHERE {
  <http://debitcard.org/transaction/1> <http://debitcard.org/schema#date> ?d
}

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT DISTINCT ?country ?countryLabel WHERE {
  ?txn <http://debit_card_specializing.org/transactions_1k#Date> ?date .
  ?txn <http://debit_card_specializing.org/transactions_1k#GasStationID> ?gsid .
  ?gs <http://debit_card_specializing.org/gasstations#GasStationID> ?gsid .
  ?gs <http://debit_card_specializing.org/gasstations#Country> ?country .
  OPTIONAL {
    ?country rdfs:label ?countryLabel .
  }
  FILTER ( regex( str( ?date ) , "^2013-06" ) )
}
ORDER BY ?countryLabel

SELECT ?customer ?nationality WHERE {
  ?tx <http://debit_card_specializing.org/transactions_1k#Amount> 548.4 .
  ?tx <http://debit_card_specializing.org/transactions_1k#Time> "2012-08-24" .
  ?tx <http://debit_card_specializing.org/transactions_1k#CustomerID> ?custID .
  ?customer <http://debit_card_specializing.org/customers#CustomerID> ?custID .
  OPTIONAL {
    ?customer <http://debit_card_specializing.org/customers#Nationality> ?nationality .
  }
}
LIMIT 10

SELECT ?total ?eur ( ( ?eur / ?total ) * 100 AS ?percentage ) WHERE {
  {
    SELECT ( COUNT( DISTINCT ?c ) AS ?total ) WHERE {
      ?c a <http://debitcard.org/schema#Customer>
    }
  }
  {
    SELECT ( COUNT( DISTINCT ?c2 ) AS ?eur ) WHERE {
      ?c2 <http://debitcard.org/schema#currency> "EUR"
    }
  }
}
LIMIT 1

PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?cust ?cid ?sum2012 ?sum2013 ?decreaseRate WHERE {
  ?t <http://debitcard.org/schema#pricePerUnit> 634.8 .
  ?t <http://debitcard.org/schema#date> "2012-08-25" ^^ xsd:date .
  ?t <http://debitcard.org/schema#cardUsed> ?cid .
  ?cust <http://debitcard.org/schema#customerID> ?cid .
  {
    SELECT ?cust ( SUM( xsd:decimal ( ?v ) ) AS ?sum2012 ) WHERE {
      ?cons <http://debitcard.org/schema#forCustomer> ?cust ; <http://debitcard.org/schema#consumptionValue> ?v ; <http://debitcard.org/schema#date> ?ym .
      FILTER ( STRSTARTS( STR( ?ym ) , "2012" ) )
    }
    GROUP BY ?cust
  }
  {
    SELECT ?cust ( SUM( xsd:decimal ( ?v2 ) ) AS ?sum2013 ) WHERE {
      ?cons2 <http://debitcard.org/schema#forCustomer> ?cust ; <http://debitcard.org/schema#consumptionValue> ?v2 ; <http://debitcard.org/schema#date> ?ym2 .
      FILTER ( STRSTARTS( STR( ?ym2 ) , "2013" ) )
    }
    GROUP BY ?cust
  }
  BIND( ( ( ?sum2012 - ?sum2013 ) / ?sum2012 ) AS ?decreaseRate )
}
LIMIT 50

SELECT ?total ?premium ?percentage WHERE {
  {
    SELECT ( COUNT( DISTINCT ?gs ) AS ?total ) WHERE {
      ?gs <http://debitcard.org/schema#country> "SVK" .
      ?gs <http://debitcard.org/schema#segment> ?seg .
    }
  }
  {
    SELECT ( COUNT( DISTINCT ?pgs ) AS ?premium ) WHERE {
      ?pgs <http://debitcard.org/schema#country> "SVK" .
      ?pgs <http://debitcard.org/schema#segment> "Premium" .
    }
  }
  BIND( ( ?premium * 100.0 ) / ?total AS ?percentage )
}

SELECT ?customer ?spentAtGas ?spentJan2012 WHERE {
  BIND( <http://debitcard.org/customer/38508> AS ?customer ) OPTIONAL {
    SELECT ?customer ( SUM( ?tp ) AS ?spentAtGas ) WHERE {
      ?t <http://debitcard.org/schema#madeBy> ?customer ; <http://debitcard.org/schema#totalPrice> ?tp ; <http://debitcard.org/schema#atStation> ?gs .
    }
    GROUP BY ?customer
  }
  OPTIONAL {
    SELECT ?customer ( SUM( ?tp2 ) AS ?spentJan2012 ) WHERE {
      ?t2 <http://debitcard.org/schema#madeBy> ?customer ; <http://debitcard.org/schema#totalPrice> ?tp2 ; <http://debitcard.org/schema#date> ?d2 .
      FILTER ( STRSTARTS( STR( ?d2 ) , "2012-01" ) )
    }
    GROUP BY ?customer
  }
}

PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?customer ( SUM( xsd:decimal ( ?amt ) ) AS ?totalSpent ) ( AVG( xsd:decimal ( ?price ) ) AS ?avgPricePerItem ) ?currency WHERE {
  ?t <http://debit_card_specializing.org/transactions_1k#CustomerID> ?customer .
  ?t <http://debit_card_specializing.org/transactions_1k#Amount> ?amt .
  OPTIONAL {
    ?t <http://debit_card_specializing.org/transactions_1k#Price> ?price .
  }
  OPTIONAL {
    ?customer <http://debit_card_specializing.org/customers#Currency> ?currency .
  }
}
GROUP BY ?customer ?currency
ORDER BY DESC ( ?totalSpent )
LIMIT 1

PREFIX trans: <http://debit_card_specializing.org/transactions_1k#>
PREFIX ym: <http://debit_card_specializing.org/yearmonth#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?customer ?yearmonth_record ?consumption WHERE {
  ?tx trans:ProductID ?prodVal .
  FILTER ( ?prodVal = <http://debit_card_specializing.org/products/ProductID=5> || ( isLiteral( ?prodVal ) && ( STR( ?prodVal ) = "5" || STR( ?prodVal ) = "ProductID=5" ) ) ) ?tx trans:Price ?price .
  OPTIONAL {
    ?tx trans:Amount ?amount
  }
  ?tx trans:CustomerID ?customer .
  BIND( xsd:decimal ( STR( ?price ) ) AS ?pdec ) BIND( IF( bound( ?amount ) , xsd:decimal ( STR( ?amount ) ) , xsd:decimal ( "1" ) ) AS ?adec ) BIND( ?pdec / ?adec AS ?unitPrice ) FILTER ( ?unitPrice > 29 ) ?yearmonth_record ym:CustomerID ?customer ; ym:Date "201208" ; ym:Consumption ?consumption .
}

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?member ?major ?majorLabel WHERE {
  ?member rdfs:label "Angela Sanders" .
  ?member <http://studentclub.org/schema#hasMajor> ?major .
  OPTIONAL {
    ?major rdfs:label ?majorLabel .
  }
}
LIMIT 10

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX schema: <http://schema.org/>
SELECT ( COUNT( DISTINCT ?member ) AS ?count ) WHERE {
  {
    ?event <http://student_club.org/event#event_name> ?ename .
  } UNION {
    ?event rdfs:label ?ename .
  } UNION {
    ?event schema:name ?ename .
  }
  FILTER ( regex( str( ?ename ) , "women.*soccer" , "i" ) ) ?att <http://student_club.org/attendance#link_to_event> ?event .
  ?att <http://student_club.org/attendance#link_to_member> ?member .
  ?member <http://student_club.org/member#t_shirt_size> ?size .
  FILTER ( LCASE( STR( ?size ) ) IN ( "m" , "medium" , "med" ) )
}

SELECT ( COUNT( ?e ) AS ?meetingCount ) WHERE {
  {
    SELECT ?e ( COUNT( DISTINCT ?m ) AS ?attCount ) WHERE {
      ?e <http://studentclub.org/schema#attendedBy> ?m .
    }
    GROUP BY ?e
  }
  FILTER ( ?attCount > 10 ) ?e <http://studentclub.org/schema#eventType> ?type .
  FILTER ( str( ?type ) = "Meeting" )
}

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?event ?label ( COUNT( DISTINCT ?member ) AS ?attCount ) WHERE {
  ?event <http://studentclub.org/schema#attendedBy> ?member .
  ?event rdfs:label ?label .
  FILTER ( ! regex( lcase( str( ?label ) ) , "attendance" ) ) FILTER NOT EXISTS {
    ?event <http://studentclub.org/schema#eventType> ?et .
    FILTER ( regex( lcase( str( ?et ) ) , "fundrais" ) )
  }
}
GROUP BY ?event ?label
HAVING ( COUNT( DISTINCT ?member ) > 20 )
ORDER BY DESC ( ?attCount )
LIMIT 100

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?expense ?expenseLabel ?isApproved ?cost ?budget ?budgetLabel WHERE {
  ?budget <http://studentclub.org/schema#forEvent> <http://studentclub.org/event/recc8dizaKrSz3GmH> .
  OPTIONAL {
    ?budget rdfs:label ?budgetLabel
  }
  ?expense <http://studentclub.org/schema#linkedToBudget> ?budget .
  OPTIONAL {
    ?expense rdfs:label ?expenseLabel
  }
  OPTIONAL {
    ?expense <http://studentclub.org/schema#isApproved> ?isApproved
  }
  OPTIONAL {
    ?expense <http://studentclub.org/schema#cost> ?cost
  }
}
ORDER BY ?expense

PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?member ( AVG( ?eventSpend ) AS ?avgSpend ) WHERE {
  ?member <http://student_club.org/member#first_name> "Elijah" ; <http://student_club.org/member#last_name> "Allen" .
  {
    SELECT ?member ?event ( SUM( xsd:decimal ( ?cost ) ) AS ?eventSpend ) WHERE {
      {
        ?exp <http://student_club.org/expense#link_to_member> ?member ; <http://student_club.org/expense#cost> ?cost ; <http://student_club.org/expense#link_to_event> ?event .
      } UNION {
        ?exp <http://student_club.org/expense#link_to_member> ?member ; <http://student_club.org/expense#cost> ?cost ; <http://student_club.org/expense#ref-link_to_budget> ?budget .
        ?budget <http://student_club.org/budget#link_to_event> ?event .
      }
      ?event <http://student_club.org/event#event_date> ?edate .
      FILTER ( regex( str( ?edate ) , "-09-" ) || regex( str( ?edate ) , "-10-" ) )
    }
    GROUP BY ?member ?event
  }
}
GROUP BY ?member

PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ( ?total2019 - ?total2020 AS ?difference ) WHERE {
  {
    SELECT ( SUM( xsd:decimal ( ?amount ) ) AS ?total2019 ) WHERE {
      ?budget a <http://studentclub.org/schema#Budget> ; <http://studentclub.org/schema#amountSpent> ?amount ; <http://studentclub.org/schema#forEvent> ?event .
      ?event <http://studentclub.org/schema#eventDate> ?date .
      BIND( substr( str( ?date ) , 1 , 4 ) AS ?year ) .
      FILTER ( ?year = "2019" )
    }
  }
  {
    SELECT ( SUM( xsd:decimal ( ?amount ) ) AS ?total2020 ) WHERE {
      ?budget a <http://studentclub.org/schema#Budget> ; <http://studentclub.org/schema#amountSpent> ?amount ; <http://studentclub.org/schema#forEvent> ?event .
      ?event <http://studentclub.org/schema#eventDate> ?date .
      BIND( substr( str( ?date ) , 1 , 4 ) AS ?year ) .
      FILTER ( ?year = "2020" )
    }
  }
}

PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?income ?notes WHERE {
  ?income <http://studentclub.org/schema#incomeDate> "2019-09-14" ^^ xsd:date .
  ?income <http://studentclub.org/schema#incomeNotes> ?notes .
  ?income <http://studentclub.org/schema#incomeSource> "Fundraising" .
}

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?person ?label ?phone WHERE {
  {
    ?person rdfs:label ?label .
    FILTER ( CONTAINS( LCASE( STR( ?label ) ) , "carlo" ) && CONTAINS( LCASE( STR( ?label ) ) , "jacobs" ) )
  } UNION {
    ?person <http://student_club.org/member#first_name> ?first .
    ?person <http://student_club.org/member#last_name> ?last .
    FILTER ( CONTAINS( LCASE( STR( ?first ) ) , "carlo" ) && CONTAINS( LCASE( STR( ?last ) ) , "jacobs" ) ) OPTIONAL {
      ?person rdfs:label ?label
    }
  }
  OPTIONAL {
    ?person <http://student_club.org/member#phone> ?phone
  }
}
LIMIT 10

PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT DISTINCT ?event ?status ?eventLabel ?statusLabel WHERE {
  ?expense rdfs:label ?expenseLabel .
  FILTER ( CONTAINS( LCASE( STR( ?expenseLabel ) ) , "post cards" ) || CONTAINS( LCASE( STR( ?expenseLabel ) ) , "posters" ) ) ?expense <http://studentclub.org/schema#expenseDate> "2019-08-20" ^^ xsd:date .
  ?expense <http://studentclub.org/schema#linkedToBudget> ?budget .
  OPTIONAL {
    ?budget <http://studentclub.org/schema#forEvent> ?event .
  }
  OPTIONAL {
    ?budget <http://studentclub.org/schema#eventStatus> ?status .
  }
  OPTIONAL {
    ?event <http://studentclub.org/schema#eventStatus> ?status .
  }
  OPTIONAL {
    ?event rdfs:label ?eventLabel .
  }
  OPTIONAL {
    ?status rdfs:label ?statusLabel .
  }
}

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?member ?major ?majorLabel WHERE {
  BIND( <http://studentclub.org/member/recZN8afUWlE5fZHG> AS ?member ) ?member <http://studentclub.org/schema#hasMajor> ?major .
  OPTIONAL {
    ?major rdfs:label ?majorLabel
  }
}

