SELECT ?in_count ?out_count ?diff ?pct WHERE {
  {
    SELECT ( COUNT( DISTINCT ?p ) AS ?in_count ) WHERE {
      ?p <http://thrombosis.org/schema#admissionType> ?val .
      FILTER ( regex( str( ?val ) , "^\\+" ) ) .
      ?p <http://thrombosis.org/schema#hasSex> "Male" .
    }
  }
  {
    SELECT ( COUNT( DISTINCT ?p2 ) AS ?out_count ) WHERE {
      ?p2 <http://thrombosis.org/schema#admissionType> "-" .
      ?p2 <http://thrombosis.org/schema#hasSex> "Male" .
    }
  }
  BIND( ( ?in_count - ?out_count ) AS ?diff ) BIND( ( ?diff * 100.0 ) / ?out_count AS ?pct )
}

PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?numFemale ?numBornAfter ?percentage WHERE {
  {
    SELECT ( COUNT( DISTINCT ?p ) AS ?numFemale ) WHERE {
      ?p a <http://thrombosis.org/schema#Patient> ; <http://thrombosis.org/schema#hasSex> "Female" ; <http://thrombosis.org/schema#birthDate> ?bd .
    }
  }
  {
    SELECT ( COUNT( DISTINCT ?p2 ) AS ?numBornAfter ) WHERE {
      ?p2 a <http://thrombosis.org/schema#Patient> ; <http://thrombosis.org/schema#hasSex> "Female" ; <http://thrombosis.org/schema#birthDate> ?bd2 .
      FILTER ( xsd:date ( ?bd2 ) > "1930-12-31" ^^ xsd:date )
    }
  }
  BIND( IF( ?numFemale = 0 , 0 , ( xsd:double ( ?numBornAfter ) * 100.0 ) / xsd:double ( ?numFemale ) ) AS ?percentage )
}

