  ?exam a <http://thrombosis.org/schema#Examination> ; <http://thrombosis.org/schema#forPatient> ?patient ; <http://thrombosis.org/schema#examDate> ?examDate ; ?coagProp ?coagValue .
  FILTER ( str( ?coagValue ) = "+" ) ?patient <http://thrombosis.org/schema#birthDate> ?birthDate .
