}

PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?exam ?patient ?examDate ?birthDate ?symptoms ?diagnosis ( ( YEAR( xsd:date ( ?examDate ) ) - YEAR( xsd:date ( ?birthDate ) ) - IF( ( ( MONTH( xsd:date ( ?examDate ) ) < MONTH( xsd:date ( ?birthDate ) ) ) || ( ( MONTH( xsd:date ( ?examDate ) ) = MONTH( xsd:date ( ?birthDate ) ) ) && ( DAY( xsd:date ( ?examDate ) ) < DAY( xsd:date ( ?birthDate ) ) ) ) ) , 1 , 0 ) ) AS ?ageYears ) WHERE {
  ?exam a <http://thrombosis.org/schema#Examination> .
  ?exam <http://thrombosis.org/schema#forPatient> ?p1 .
  ?exam <http://thrombosis.org/schema#examDate> ?examDate .
  BIND( IRI( REPLACE( STR( ?p1 ) , "\\.0$" , "" ) ) AS ?patient ) ?patient <http://thrombosis.org/schema#birthDate> ?birthDate .
  OPTIONAL {
    ?exam <http://thrombosis.org/schema#symptoms> ?symptoms .
  }
  OPTIONAL {
    ?exam <http://thrombosis.org/schema#diagnosis> ?diagnosis .
  }
}
ORDER BY ASC ( ?ageYears )
LIMIT 1

SELECT ?patient ?age ( MAX( ?labDate ) AS ?labCompletedDate ) WHERE {
  {
    SELECT ?patient ( ( YEAR( ?first ) - YEAR( ?birth ) - IF( ( ( MONTH( ?first ) < MONTH( ?birth ) ) || ( MONTH( ?first ) = MONTH( ?birth ) && DAY( ?first ) < DAY( ?birth ) ) ) , 1 , 0 ) ) AS ?age ) WHERE {
      ?patient <http://thrombosis.org/schema#diagnosis> "SJS" .
      ?patient <http://thrombosis.org/schema#birthDate> ?birth .
      ?patient <http://thrombosis.org/schema#firstRecordDate> ?first .
    }
    ORDER BY DESC ( ?age )
    LIMIT 1
  }
  OPTIONAL {
    ?lab <http://thrombosis.org/schema#forPatient> ?patient ; <http://thrombosis.org/schema#testDate> ?labDate .
  }
}
GROUP BY ?patient ?age

PREFIX th: <http://thrombosis.org/schema#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?maleCount ?femaleCount ( ?maleCount / ?femaleCount AS ?male_female_ratio ) WHERE {
  {
    SELECT ( COUNT( DISTINCT ?patientM ) AS ?maleCount ) WHERE {
      ?labM th:UA ?uaM .
      ?labM th:forPatient ?patientM .
      ?patientM th:hasSex "Male" .
      FILTER ( xsd:decimal ( ?uaM ) > 7.0 )
    }
  }
  {
    SELECT ( COUNT( DISTINCT ?patientF ) AS ?femaleCount ) WHERE {
      ?labF th:UA ?uaF .
      ?labF th:forPatient ?patientF .
      ?patientF th:hasSex "Female" .
      FILTER ( xsd:decimal ( ?uaF ) > 6.0 )
    }
  }
}

PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?patient ?age ?diagnosis ?h ?testDate WHERE {
  ?lt <http://thrombosis.org/schema#HGB> ?h .
  ?lt <http://thrombosis.org/schema#forPatient> ?patient .
  ?lt <http://thrombosis.org/schema#testDate> ?testDate .
  ?patient <http://thrombosis.org/schema#birthDate> ?birth .
  OPTIONAL {
    ?patient <http://thrombosis.org/schema#diagnosis> ?diagnosis
  }
  BIND( ( YEAR( ?testDate ) - YEAR( ?birth ) - IF( ( MONTH( ?testDate ) > MONTH( ?birth ) ) || ( MONTH( ?testDate ) = MONTH( ?birth ) && DAY( ?testDate ) >= DAY( ?birth ) ) , 0 , 1 ) ) AS ?age )
}
ORDER BY DESC ( xsd:decimal ( ?h ) )
LIMIT 1

PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?patient ?exam ?aCL_IgG ?aCL_IgM ?aCL_IgA WHERE {
  ?patient <http://thrombosis.org/schema#diagnosis> "SLE" ; <http://thrombosis.org/schema#firstRecordDate> "1994-02-19" ^^ xsd:date .
  ?exam <http://thrombosis.org/schema#examDate> "1993-11-12" ^^ xsd:date ; <http://thrombosis.org/schema#forPatient> ?forP .
  FILTER ( STR( ?patient ) = REPLACE( STR( ?forP ) , "\\.0$" , "" ) ) OPTIONAL {
    ?exam <http://thrombosis.org/schema#aCL_IgG> ?aCL_IgG .
  }
  OPTIONAL {
    ?exam <http://thrombosis.org/schema#aCL_IgM> ?aCL_IgM .
  }
  OPTIONAL {
    ?exam <http://thrombosis.org/schema#aCL_IgA> ?aCL_IgA .
  }
}

PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?patient ?tchoNov ?tchoDec ( ( ( xsd:decimal ( ?tchoNov ) - xsd:decimal ( ?tchoDec ) ) / xsd:decimal ( ?tchoNov ) ) AS ?decreaseRate ) WHERE {
  BIND( <http://thrombosis.org/patient/1610433> AS ?patient ) ?labNov <http://thrombosis.org/schema#forPatient> ?patient ; <http://thrombosis.org/schema#testDate> ?dateNov ; <http://thrombosis.org/schema#T_CHO> ?tchoNov .
  ?labDec <http://thrombosis.org/schema#forPatient> ?patient ; <http://thrombosis.org/schema#testDate> ?dateDec ; <http://thrombosis.org/schema#T_CHO> ?tchoDec .
  FILTER ( SUBSTR( STR( ?dateNov ) , 1 , 7 ) = "1981-11" ) FILTER ( SUBSTR( STR( ?dateDec ) , 1 , 7 ) = "1981-12" )
}

PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ( COUNT( DISTINCT ?patient ) AS ?count ) WHERE {
  {
    SELECT ( AVG( xsd:decimal ( ?aAll ) ) AS ?avgA ) WHERE {
      ?examAll <http://thrombosis.org/schema#aCL_IgM> ?aAll .
    }
  }
  ?exam <http://thrombosis.org/schema#aCL_IgM> ?aVal ; <http://thrombosis.org/schema#thrombosisSeverity> ?thr ; <http://thrombosis.org/schema#anaPattern> ?ana ; <http://thrombosis.org/schema#forPatient> ?patient .
  FILTER ( xsd:integer ( ?thr ) = 2 ) FILTER ( str( ?ana ) = "S" ) FILTER ( xsd:decimal ( ?aVal ) > ( ?avgA * 1.2 ) )
}

PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?femaleCount ?totalCount ( IF( ?totalCount > 0 , ( ?femaleCount * 100.0 ) / ?totalCount , 0 ) AS ?percentage ) WHERE {
  {
    SELECT ( COUNT( DISTINCT ?p ) AS ?totalCount ) WHERE {
      ?p rdf:type <http://thrombosis.org/schema#Patient> ; <http://thrombosis.org/schema#birthDate> ?birthDate ; <http://thrombosis.org/schema#diagnosis> ?diag .
      FILTER ( YEAR( ?birthDate ) = 1980 ) FILTER ( regex( str( ?diag ) , "\\bRA\\b" , "i" ) )
    }
  }
  {
    SELECT ( COUNT( DISTINCT ?p2 ) AS ?femaleCount ) WHERE {
      ?p2 rdf:type <http://thrombosis.org/schema#Patient> ; <http://thrombosis.org/schema#birthDate> ?b2 ; <http://thrombosis.org/schema#diagnosis> ?d2 ; <http://thrombosis.org/schema#hasSex> ?sex .
      FILTER ( YEAR( ?b2 ) = 1980 ) FILTER ( regex( str( ?d2 ) , "\\bRA\\b" , "i" ) ) FILTER ( lcase( str( ?sex ) ) = "female" )
    }
  }
}

PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
ASK {
  {
    SELECT ?ua ?sex WHERE {
      <http://thrombosis.org/patient/57266> <http://thrombosis.org/schema#hasSex> ?sex .
      ?lab <http://thrombosis.org/schema#forPatient> <http://thrombosis.org/patient/57266> ; <http://thrombosis.org/schema#UA> ?ua ; <http://thrombosis.org/schema#testDate> ?date .
    }
    ORDER BY DESC ( ?date )
    LIMIT 1
  }
  FILTER ( ( ?sex = "Male" && xsd:decimal ( ?ua ) >= 3.4 && xsd:decimal ( ?ua ) <= 7.0 ) || ( ?sex = "Female" && xsd:decimal ( ?ua ) >= 2.4 && xsd:decimal ( ?ua ) <= 6.0 ) )
}

PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT DISTINCT ?patient ?patientLabel WHERE {
  ?patient a <http://thrombosis.org/schema#Patient> ; <http://thrombosis.org/schema#hasSex> "Male" .
  ?lab a <http://thrombosis.org/schema#LaboratoryTest> ; <http://thrombosis.org/schema#forPatient> ?patient ; <http://thrombosis.org/schema#GPT> ?gpt .
  FILTER ( xsd:decimal ( ?gpt ) > 40 ) OPTIONAL {
    ?patient rdfs:label ?patientLabel
  }
}
LIMIT 1000

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT DISTINCT ?patient ?patientLabel ?sex ?birthDate WHERE {
  ?lab <http://thrombosis.org/schema#UN> ?un .
  FILTER ( ?un = 20 ) ?lab <http://thrombosis.org/schema#forPatient> ?patient .
  OPTIONAL {
    ?patient rdfs:label ?patientLabel .
  }
  OPTIONAL {
    ?patient <http://thrombosis.org/schema#hasSex> ?sex .
  }
  OPTIONAL {
    ?patient <http://thrombosis.org/schema#birthDate> ?birthDate .
  }
}
ORDER BY ?patient

PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ( AVG( xsd:double ( ?ageYears ) ) AS ?averageAge ) WHERE {
  ?lab <http://thrombosis.org/schema#T_CHO> ?tcho ; <http://thrombosis.org/schema#forPatient> ?patient ; <http://thrombosis.org/schema#testDate> ?testDate .
  ?patient <http://thrombosis.org/schema#birthDate> ?birthDate ; <http://thrombosis.org/schema#hasSex> ?sex .
  BIND( ( YEAR( ?testDate ) - YEAR( ?birthDate ) ) AS ?ageYears ) FILTER ( ?tcho >= 240 ) FILTER ( regex( str( ?sex ) , "^male$" , "i" ) )
}

SELECT DISTINCT ?patient ?diagnosis ?age WHERE {
  {
    SELECT ?patient ( MIN( ?testDate ) AS ?firstLowDate ) WHERE {
      ?lab <http://thrombosis.org/schema#RBC> ?rbc .
      FILTER ( ?rbc < 4 ) ?lab <http://thrombosis.org/schema#forPatient> ?patient .
      ?lab <http://thrombosis.org/schema#testDate> ?testDate .
    }
    GROUP BY ?patient
  }
  ?patient <http://thrombosis.org/schema#diagnosis> ?diagnosis .
  ?patient <http://thrombosis.org/schema#birthDate> ?birthDate .
  BIND( ( YEAR( ?firstLowDate ) - YEAR( ?birthDate ) - IF( ( ( MONTH( ?firstLowDate ) > MONTH( ?birthDate ) ) || ( MONTH( ?firstLowDate ) = MONTH( ?birthDate ) && DAY( ?firstLowDate ) >= DAY( ?birthDate ) ) ) , 0 , 1 ) ) AS ?age )
}
ORDER BY ?patient

PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?patient ( ( xsd:integer ( substr( str( ?firstVisitDate ) , 1 , 4 ) ) - xsd:integer ( substr( str( ?birthDate ) , 1 , 4 ) ) ) AS ?age ) WHERE {
  ?lt a <http://thrombosis.org/schema#LaboratoryTest> ; <http://thrombosis.org/schema#forPatient> ?patient ; <http://thrombosis.org/schema#HCT> ?hct .
  ?patient <http://thrombosis.org/schema#birthDate> ?birthDate ; <http://thrombosis.org/schema#firstVisitDate> ?firstVisitDate ; <http://thrombosis.org/schema#hasSex> ?sex .
  FILTER ( ( str( ?sex ) = "Male" && xsd:decimal ( ?hct ) > 52 ) || ( str( ?sex ) = "Female" && xsd:decimal ( ?hct ) > 48 ) ) OPTIONAL {
    ?patient rdfs:label ?label
  }
}
GROUP BY ?patient ?birthDate ?firstVisitDate
HAVING ( COUNT( DISTINCT ?lt ) >= 2 )
ORDER BY ?patient

PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?lowCount ?highCount ?difference WHERE {
  {
    SELECT ( COUNT( DISTINCT ?patientLow ) AS ?lowCount ) WHERE {
      ?lab a <http://thrombosis.org/schema#LaboratoryTest> ; <http://thrombosis.org/schema#PLT> ?plt ; <http://thrombosis.org/schema#forPatient> ?patientLow .
      FILTER ( xsd:decimal ( ?plt ) < 150 )
    }
  }
  {
    SELECT ( COUNT( DISTINCT ?patientHigh ) AS ?highCount ) WHERE {
      ?lab2 a <http://thrombosis.org/schema#LaboratoryTest> ; <http://thrombosis.org/schema#PLT> ?plt2 ; <http://thrombosis.org/schema#forPatient> ?patientHigh .
      FILTER ( xsd:decimal ( ?plt2 ) > 450 )
    }
  }
  BIND( xsd:integer ( ?lowCount - ?highCount ) AS ?difference )
}

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT DISTINCT ?patient ?patientLabel WHERE {
  ?lab a <http://thrombosis.org/schema#LaboratoryTest> ; <http://thrombosis.org/schema#forPatient> ?patient ; <http://thrombosis.org/schema#testDate> ?testDate ; <http://thrombosis.org/schema#PLT> ?plt .
  ?patient <http://thrombosis.org/schema#birthDate> ?birthDate .
  FILTER ( YEAR( ?testDate ) = 1984 ) FILTER ( ( YEAR( ?testDate ) - YEAR( ?birthDate ) ) < 50 ) FILTER ( ?plt >= 150 && ?plt <= 450 ) OPTIONAL {
    ?patient rdfs:label ?patientLabel .
  }
}
ORDER BY ?patient

PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?femaleAbnormal ?totalPatients ?percentage WHERE {
  {
    SELECT ( COUNT( DISTINCT ?p ) AS ?totalPatients ) WHERE {
      ?p a <http://thrombosis.org/schema#Patient> ; <http://thrombosis.org/schema#birthDate> ?birthDate .
      BIND( ( YEAR( NOW () ) - YEAR( ?birthDate ) - IF( ( MONTH( NOW () ) < MONTH( ?birthDate ) ) || ( MONTH( NOW () ) = MONTH( ?birthDate ) && DAY( NOW () ) < DAY( ?birthDate ) ) , 1 , 0 ) ) AS ?age ) FILTER ( ?age > 55 )
    }
  }
  {
    SELECT ( COUNT( DISTINCT ?p2 ) AS ?femaleAbnormal ) WHERE {
      ?p2 a <http://thrombosis.org/schema#Patient> ; <http://thrombosis.org/schema#birthDate> ?birthDate2 ; <http://thrombosis.org/schema#hasSex> ?sex .
      BIND( ( YEAR( NOW () ) - YEAR( ?birthDate2 ) - IF( ( MONTH( NOW () ) < MONTH( ?birthDate2 ) ) || ( MONTH( NOW () ) = MONTH( ?birthDate2 ) && DAY( NOW () ) < DAY( ?birthDate2 ) ) , 1 , 0 ) ) AS ?age2 ) FILTER ( ?age2 > 55 ) FILTER ( LCASE( STR( ?sex ) ) = "female" ) ?lt <http://thrombosis.org/schema#forPatient> ?p2 ; <http://thrombosis.org/schema#PT> ?pt .
      FILTER ( xsd:decimal ( ?pt ) > 13.5 )
    }
  }
  BIND( ( xsd:decimal ( ?femaleAbnormal ) * 100.0 ) / xsd:decimal ( ?totalPatients ) AS ?percentage )
}

SELECT ( COUNT( DISTINCT ?patient ) AS ?count ) WHERE {
  ?lab <http://thrombosis.org/schema#IGG> ?igg ; <http://thrombosis.org/schema#forPatient> ?patient .
  ?exam <http://thrombosis.org/schema#forPatient> ?patient ; <http://thrombosis.org/schema#symptoms> ?sym .
  FILTER ( ?igg >= 700 && ?igg <= 1600 )
}

PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ( COUNT( DISTINCT ?patient ) AS ?count ) WHERE {
  ?lab <http://thrombosis.org/schema#CRP> ?val .
  ?lab <http://thrombosis.org/schema#forPatient> ?patient .
  FILTER ( isLiteral( ?val ) ) FILTER ( regex( str( ?val ) , '^[0-9]+(\\.[0-9]+)?$' ) ) FILTER ( xsd:decimal ( str( ?val ) ) > 5 )
}

SELECT ( COUNT( DISTINCT ?patient ) AS ?count ) WHERE {
  ?lab <http://thrombosis.org/schema#RNP> ?rnpVal .
  ?lab <http://thrombosis.org/schema#forPatient> ?patient .
  ?patient <http://thrombosis.org/schema#admissionType> ?admit .
  FILTER ( STR( ?admit ) = "+" ) FILTER ( STR( ?rnpVal ) = "negative" || STR( ?rnpVal ) = "0" )
}

PREFIX schema: <http://schema.org/>
SELECT ( COUNT( DISTINCT ?patient ) AS ?count ) WHERE {
  ?lab a schema:LaboratoryTest ; schema:SM ?sm ; schema:forPatient ?patient .
  FILTER ( ?sm = "negative" || ?sm = "negative" @en || ?sm = "0" || ?sm = 0 ) FILTER NOT EXISTS {
    ?exam schema:forPatient ?patient ; schema:thrombosisSeverity ?sev .
    FILTER ( ?sev > 0 )
  }
}

PREFIX t: <http://thrombosis.org/schema#>
SELECT ( COUNT( DISTINCT ?patient ) AS ?count ) WHERE {
  ?lab a t:LaboratoryTest ; t:SC170 ?sc ; t:forPatient ?patient .
  ?patient t:hasSex ?sex .
  FILTER ( lcase( str( ?sex ) ) = "female" ) FILTER ( lcase( str( ?sc ) ) = "negative" || str( ?sc ) = "0" || str( ?sc ) = "0.0" ) FILTER NOT EXISTS {
    ?exam a t:Examination ; t:forPatient ?patient ; t:symptoms ?sym .
  }
}

SELECT ( COUNT( DISTINCT ?patient ) AS ?count ) WHERE {
  ?lab <http://thrombosis.org/schema#CPK> ?cpk ; <http://thrombosis.org/schema#forPatient> ?patient .
  FILTER ( ?cpk >= 20 && ?cpk <= 200 ) ?exam <http://thrombosis.org/schema#forPatient> ?patient .
  {
    ?exam <http://thrombosis.org/schema#coagulationLAC> "+" .
  } UNION {
    ?exam <http://thrombosis.org/schema#coagulationKCT> "+" .
  } UNION {
    ?exam <http://thrombosis.org/schema#coagulationRVVT> "+" .
  }
}

PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?league ( SUM( ?matchGoals ) AS ?totalGoals ) ?leagueLabel WHERE {
  ?match a <http://europeanfootball.org/schema#Match> ; <http://europeanfootball.org/schema#season> ?season ; <http://europeanfootball.org/schema#homeTeamGoal> ?home ; <http://europeanfootball.org/schema#awayTeamGoal> ?away ; <http://europeanfootball.org/schema#playedInLeague> ?league .
  BIND( ( xsd:integer ( ?home ) + xsd:integer ( ?away ) ) AS ?matchGoals ) OPTIONAL {
    ?league rdfs:label ?leagueLabel
  }
  FILTER ( CONTAINS( LCASE( STR( ?season ) ) , "2016" ) )
}
GROUP BY ?league ?leagueLabel
ORDER BY DESC ( ?totalGoals )
LIMIT 1

PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?awayTeam ?awayTeamLabel ?awayWins WHERE {
  {
    SELECT ?awayTeam ( COUNT( ?m ) AS ?awayWins ) WHERE {
      ?m <http://europeanfootball.org/schema#playedInLeague> <http://europeanfootball.org/league/19694> ; <http://europeanfootball.org/schema#season> "2010/2011" ; <http://europeanfootball.org/schema#awayTeamApiId> ?awayTeam ; <http://europeanfootball.org/schema#homeTeamGoal> ?homeGoals ; <http://europeanfootball.org/schema#awayTeamGoal> ?awayGoals .
      FILTER ( xsd:integer ( ?awayGoals ) > xsd:integer ( ?homeGoals ) )
    }
    GROUP BY ?awayTeam
  }
  {
    SELECT ( MAX( ?aw ) AS ?maxWins ) WHERE {
      {
        SELECT ?awayTeam2 ( COUNT( ?m2 ) AS ?aw ) WHERE {
          ?m2 <http://europeanfootball.org/schema#playedInLeague> <http://europeanfootball.org/league/19694> ; <http://europeanfootball.org/schema#season> "2010/2011" ; <http://europeanfootball.org/schema#awayTeamApiId> ?awayTeam2 ; <http://europeanfootball.org/schema#homeTeamGoal> ?hg2 ; <http://europeanfootball.org/schema#awayTeamGoal> ?ag2 .
          FILTER ( xsd:integer ( ?ag2 ) > xsd:integer ( ?hg2 ) )
        }
        GROUP BY ?awayTeam2
      }
    }
  }
  FILTER ( ?awayWins = ?maxWins ) OPTIONAL {
    ?awayTeam rdfs:label ?awayTeamLabel
  }
}
ORDER BY DESC ( ?awayWins )

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?team ?teamLabel ( MAX( ?speed ) AS ?maxSpeed ) WHERE {
  ?ta a <http://europeanfootball.org/schema#TeamAttributes> ; <http://europeanfootball.org/schema#buildUpPlaySpeed> ?speed ; <http://europeanfootball.org/schema#teamFifaApiId> ?fid .
  ?team a <http://europeanfootball.org/schema#Team> ; <http://europeanfootball.org/schema#teamFifaApiId> ?fid .
  OPTIONAL {
    ?team rdfs:label ?teamLabel
  }
}
GROUP BY ?team ?teamLabel
ORDER BY DESC ( ?maxSpeed )
LIMIT 4

PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?league ( COUNT( ?m ) AS ?drawCount ) ?leagueLabel WHERE {
  ?m a <http://europeanfootball.org/schema#Match> ; <http://europeanfootball.org/schema#season> ?season ; <http://europeanfootball.org/schema#playedInLeague> ?league ; <http://europeanfootball.org/schema#homeTeamGoal> ?hg ; <http://europeanfootball.org/schema#awayTeamGoal> ?ag .
  FILTER ( xsd:int ( ?hg ) = xsd:int ( ?ag ) ) FILTER ( CONTAINS( STR( ?season ) , "2016" ) ) OPTIONAL {
    ?league rdfs:label ?leagueLabel
  }
}
GROUP BY ?league ?leagueLabel
ORDER BY DESC ( ?drawCount )
LIMIT 1

PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT DISTINCT ?player ?playerLabel ?age WHERE {
  ?attr <http://europeanfootball.org/schema#forPlayer> ?player ; <http://europeanfootball.org/schema#playerAttributesDate> ?attrDate ; <http://europeanfootball.org/schema#sprintSpeed> ?sprint .
  FILTER ( ?sprint >= 97 ) .
  FILTER ( ?attrDate >= "2013-01-01T00:00:00" ^^ xsd:dateTime && ?attrDate <= "2015-12-31T23:59:59" ^^ xsd:dateTime ) .
  ?player <http://europeanfootball.org/schema#birthDay> ?birth .
  OPTIONAL {
    ?player rdfs:label ?playerLabel .
  }
  BIND( ( YEAR( NOW () ) - YEAR( ?birth ) - IF( ( MONTH( NOW () ) < MONTH( ?birth ) ) || ( MONTH( NOW () ) = MONTH( ?birth ) && DAY( NOW () ) < DAY( ?birth ) ) , 1 , 0 ) ) AS ?age )
}
ORDER BY DESC ( ?age )

PREFIX ef: <http://europeanfootball.org/schema#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?league ?leagueLabel ( COUNT( ?match ) AS ?matches ) WHERE {
  ?match a ef:Match .
  ?match ef:playedInLeague ?league .
  OPTIONAL {
    ?league rdfs:label ?leagueLabel
  }
}
GROUP BY ?league ?leagueLabel
ORDER BY DESC ( ?matches )
LIMIT 1

PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT DISTINCT ?team ?longName WHERE {
  ?attr a <http://europeanfootball.org/schema#TeamAttributes> ; <http://europeanfootball.org/schema#teamFifaApiId> ?fifaId ; <http://europeanfootball.org/schema#buildUpPlayPassing> ?val .
  FILTER ( CONTAINS( STR( ?attr ) , "2012" ) ) .
  ?team <http://europeanfootball.org/schema#teamFifaApiId> ?fifaId .
  OPTIONAL {
    ?team <http://europeanfootball.org/schema#teamLongName> ?teamLongName
  }
  .
  OPTIONAL {
    ?team rdfs:label ?label
  }
  .
  BIND( COALESCE ( ?teamLongName , ?label ) AS ?longName ) .
  {
    SELECT ( AVG( xsd:decimal ( ?v ) ) AS ?avgVal ) WHERE {
      ?a <http://europeanfootball.org/schema#buildUpPlayPassing> ?v .
      FILTER ( CONTAINS( STR( ?a ) , "2012" ) ) .
    }
  }
  FILTER ( xsd:decimal ( ?val ) > ?avgVal )
}
ORDER BY ?longName

PREFIX ef: <http://europeanfootball.org/schema#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?total ?left ( ?left * 100.0 / ?total AS ?percentage ) WHERE {
  {
    SELECT ( COUNT( DISTINCT ?player ) AS ?total ) WHERE {
      ?player rdf:type ef:Player .
      ?player ef:birthDay ?dob .
      BIND( xsd:integer ( substr( str( ?dob ) , 1 , 4 ) ) AS ?year ) FILTER ( ?year >= 1987 && ?year <= 1992 )
    }
  }
  {
    SELECT ( COUNT( DISTINCT ?playerLeft ) AS ?left ) WHERE {
      ?playerLeft rdf:type ef:Player .
      ?playerLeft ef:birthDay ?dob2 .
      BIND( xsd:integer ( substr( str( ?dob2 ) , 1 , 4 ) ) AS ?year2 ) FILTER ( ?year2 >= 1987 && ?year2 <= 1992 ) ?pa rdf:type ef:PlayerAttributes .
      ?pa ef:forPlayer ?playerLeft .
      ?pa ef:preferredFoot ?foot .
      FILTER ( lcase( str( ?foot ) ) = "left" )
