      ?rr f1:byDriver <http://formula1.org/driver/1> .
      ?rr f1:forRace ?race .
      ?race f1:raceDate ?raceDate .
      FILTER ( ?raceDate >= "2010-01-01" ^^ xsd:date )
    }
  }
  {
    SELECT ( COUNT( DISTINCT ?race ) AS ?wins ) WHERE {
      ?rr2 a f1:RaceResult .
      ?rr2 f1:byDriver <http://formula1.org/driver/1> .
      ?rr2 f1:forRace ?race .
      ?rr2 f1:positionOrder 1 .
      ?race f1:raceDate ?raceDate2 .
      FILTER ( ?raceDate2 >= "2010-01-01" ^^ xsd:date )
    }
  }
