PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?race ?winner ?winnerMs ?last ?lastMs ( ( ( ?lastMs - ?winnerMs ) / ?lastMs ) * 100 AS ?percentFaster ) WHERE {
  BIND( <RACE_IRI> AS ?race ) ?resW a <http://formula1.org/schema#RaceResult> ; <http://formula1.org/schema#forRace> ?race ; <http://formula1.org/schema#positionOrder> 1 ; <http://formula1.org/schema#byDriver> ?winner ; <http://formula1.org/schema#milliseconds> ?winnerMs .
  {
    SELECT ?race ( MAX( xsd:integer ( ?pos ) ) AS ?lastPos ) WHERE {
      ?r a <http://formula1.org/schema#RaceResult> ; <http://formula1.org/schema#forRace> ?race ; <http://formula1.org/schema#positionOrder> ?pos .
      FILTER ( regex( str( ?pos ) , "^[0-9]+$" ) )
    }
    GROUP BY ?race
  }
  ?resL a <http://formula1.org/schema#RaceResult> ; <http://formula1.org/schema#forRace> ?race ; <http://formula1.org/schema#positionOrder> ?lastPos ; <http://formula1.org/schema#byDriver> ?last ; <http://formula1.org/schema#milliseconds> ?lastMs .
  FILTER ( xsd:integer ( ?winnerMs ) >= 0 && xsd:integer ( ?lastMs ) > 0 )
}
