PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ( COUNT( ?constructor ) AS ?count ) WHERE {
  {
    SELECT ?constructor ( COUNT( DISTINCT ?res ) AS ?zeroCount ) WHERE {
      ?constructor rdf:type <http://formula1.org/schema#Constructor> .
      ?constructor <http://formula1.org/schema#nationality> "Japanese" .
      ?res rdf:type <http://formula1.org/schema#ConstructorResult> ; <http://formula1.org/schema#byConstructor> ?constructor ; <http://formula1.org/schema#points> ?points .
      FILTER ( ?points = 0 || ?points = "0" || ?points = "0" ^^ xsd:decimal || ?points = "0" ^^ xsd:int )
    }
    GROUP BY ?constructor
    HAVING ( ?zeroCount = 2 )
  }
}

PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?season ?year ( COUNT( ?res ) AS ?starts ) ( SUM( IF( BOUND( ?pos ) , 1 , 0 ) ) AS ?finishes ) ( ( xsd:decimal ( SUM( IF( BOUND( ?pos ) , 1 , 0 ) ) ) * 100 ) / xsd:decimal ( COUNT( ?res ) ) AS ?completionPercentage ) WHERE {
  ?driver <http://formula1.org/schema#nationality> ?nat .
  FILTER ( REGEX( STR( ?nat ) , "jap" , "i" ) ) .
  ?res a <http://formula1.org/schema#RaceResult> ; <http://formula1.org/schema#byDriver> ?driver ; <http://formula1.org/schema#forRace> ?race .
  ?race <http://formula1.org/schema#raceYear> ?season .
  ?season <http://formula1.org/schema#seasonYear> ?seasonYear .
  BIND( xsd:integer ( STR( ?seasonYear ) ) AS ?year ) FILTER ( ?year >= 2007 && ?year <= 2009 ) OPTIONAL {
    ?res <http://formula1.org/schema#positionOrder> ?pos .
  }
}
GROUP BY ?season ?year
ORDER BY ?year

PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?season ?seasonYear ( AVG( ?seconds ) AS ?avgSeconds ) ?seasonLabel WHERE {
  ?result a <http://formula1.org/schema#RaceResult> ; <http://formula1.org/schema#positionOrder> 1 ; <http://formula1.org/schema#forRace> ?race ; <http://formula1.org/schema#finishTime> ?finishTime .
  ?race <http://formula1.org/schema#raceYear> ?season .
  ?season <http://formula1.org/schema#seasonYear> ?seasonYear .
  OPTIONAL {
    ?season rdfs:label ?seasonLabel
  }
  BIND( STRBEFORE( ?finishTime , ":" ) AS ?hoursStr ) BIND( STRAFTER( ?finishTime , ":" ) AS ?rest ) BIND( STRBEFORE( ?rest , ":" ) AS ?minutesStr ) BIND( STRAFTER( ?rest , ":" ) AS ?secsStr ) BIND( ( xsd:decimal ( ?hoursStr ) * 3600.0 ) + ( xsd:decimal ( ?minutesStr ) * 60.0 ) + xsd:decimal ( ?secsStr ) AS ?seconds ) FILTER ( ?seasonYear < "1975" ^^ xsd:gYear )
}
GROUP BY ?season ?seasonYear ?seasonLabel
ORDER BY ?seasonYear

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?result ?race ?raceLabel ?fastestLapNumber WHERE {
