PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?race ( AVG( xsd:decimal ( ?speed ) ) AS ?avgSpeed ) ( COUNT( ?s ) AS ?count ) WHERE {
  BIND( <http://formula1.org/race/5> AS ?race ) ?s <http://formula1.org/schema#forRace> ?race ; <http://formula1.org/schema#fastestLapSpeed> ?speed .
