PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?total ?neutral ?neutralMarvel ?percent WHERE {
  {
    SELECT ( COUNT( DISTINCT ?h ) AS ?total ) WHERE {
      ?h rdf:type <http://superhero.org/schema#Superhero>
    }
  }
  {
    SELECT ( COUNT( DISTINCT ?h2 ) AS ?neutral ) WHERE {
      ?h2 <http://superhero.org/schema#hasAlignment> ?align2 .
      FILTER ( CONTAINS( STR( ?align2 ) , "alignment/3.0" ) )
    }
  }
  {
    SELECT ( COUNT( DISTINCT ?h3 ) AS ?neutralMarvel ) WHERE {
      ?h3 <http://superhero.org/schema#hasAlignment> ?align3 .
      FILTER ( CONTAINS( STR( ?align3 ) , "alignment/3.0" ) ) .
      ?h3 <http://superhero.org/schema#publishedBy> ?pub3 .
      FILTER ( CONTAINS( STR( ?pub3 ) , "publisher/13.0" ) )
    }
  }
  BIND( ( xsd:decimal ( ?neutral ) / xsd:decimal ( ?total ) ) * 100 AS ?percent )
}

SELECT ?dc ?marvel ?dcCount ?marvelCount ( ?dcCount - ?marvelCount AS ?difference ) WHERE {
