  {
    SELECT ( COUNT( DISTINCT ?hero ) AS ?marvelCount ) WHERE {
      ?hero <http://superhero.org/schema#publishedBy> <http://superhero.org/publisher/13.0> .
    }
  }
  BIND( <http://superhero.org/publisher/4.0> AS ?dc ) BIND( <http://superhero.org/publisher/13.0> AS ?marvel )
}

