      FILTER ( xsd:integer ( ?h2 ) >= 150 && xsd:integer ( ?h2 ) <= 180 ) ?heroM <http://superhero.org/schema#publishedBy> ?pub2 .
      FILTER ( CONTAINS( STR( ?pub2 ) , "/publisher/13" ) )
    }
