    SELECT ( AVG( ?w ) AS ?avgWeight ) WHERE {
      ?x a <http://superhero.org/schema#Superhero> .
      ?x <http://superhero.org/schema#weightInKg> ?w .
    }
  }
  FILTER ( ?weight > ( ?avgWeight * 0.79 ) )
}
ORDER BY DESC ( ?weight )

