  FILTER ( CONTAINS( STR( ?label ) , "Ancestor's Chosen" ) ) .
  OPTIONAL {
    ?card <http://cardgames.org/schema#borderColor> ?borderColor .
  }
}

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?card ?text ?label WHERE {
  VALUES ?card {
    <http://cardgames.org/card/7>
  }
  ?card <http://cardgames.org/schema#text> ?text .
  OPTIONAL {
    ?card rdfs:label ?label
  }
}

SELECT ?borderlessCount ?totalCount ( ( ?borderlessCount * 100.0 ) / ?totalCount AS ?percentage ) WHERE {
  {
    SELECT ( COUNT( DISTINCT ?card ) AS ?totalCount ) WHERE {
      ?card a <http://cardgames.org/schema#Card> .
    }
  }
  {
    SELECT ( COUNT( DISTINCT ?bcard ) AS ?borderlessCount ) WHERE {
      ?bcard a <http://cardgames.org/schema#Card> ; <http://cardgames.org/schema#borderColor> ?bc .
      FILTER ( lcase( str( ?bc ) ) = "borderless" )
    }
  }
}

PREFIX cg: <http://cardgames.org/schema#>
SELECT ?frenchCount ?totalCount ?percentage WHERE {
  {
    SELECT ( COUNT( ?c ) AS ?totalCount ) WHERE {
      ?c cg:isStorySpotlight "Yes" .
    }
  }
  {
    SELECT ( COUNT( ?c2 ) AS ?frenchCount ) WHERE {
      ?c2 cg:isStorySpotlight "Yes" ; cg:language "French" .
    }
  }
  BIND( ( ?frenchCount * 100.0 ) / ?totalCount AS ?percentage )
}

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?card ?label WHERE {
  ?card <http://cardgames.org/schema#duelDeck> "a" .
  OPTIONAL {
    ?card rdfs:label ?label
  }
}
ORDER BY ?card

SELECT ( COUNT( DISTINCT ?card ) AS ?count ) WHERE {
  ?card <http://cardgames.org/schema#uuid> ?uuid .
  ?leg <http://cardgames.org/schema#legalityUUID> ?uuid ; <http://cardgames.org/schema#status> "Banned" .
  ?card <http://cardgames.org/schema#borderColor> ?border .
  FILTER ( lcase( str( ?border ) ) = "white" )
}

SELECT DISTINCT ?card ?mana WHERE {
  ?card <http://cardgames.org/schema#layout> "normal" .
  ?card <http://cardgames.org/schema#frameVersion> "2003" .
  ?card <http://cardgames.org/schema#borderColor> "black" .
  ?card <http://cardgames.org/schema#manaCost> ?mana .
  {
    ?card <http://cardgames.org/schema#availability> "paper" .
    ?card <http://cardgames.org/schema#availability> "mtgo" .
  } UNION {
    ?card <http://cardgames.org/schema#availability> ?availCombined .
    FILTER ( regex( str( ?availCombined ) , "paper" , "i" ) && regex( str( ?availCombined ) , "mtgo" , "i" ) )
  }
}
ORDER BY ?card

PREFIX cg: <http://cardgames.org/schema#>
SELECT ( SAMPLE( ?pct ) AS ?percentage ) ( GROUP_CONCAT( ?id ; separator = ", " ) AS ?ids ) WHERE {
  {
    SELECT ( ( ?textless * 100.0 ) / ?total AS ?pct ) WHERE {
      {
        SELECT ( COUNT( ?c ) AS ?total ) WHERE {
          ?c cg:isStorySpotlight "Yes" .
        }
      }
      {
        SELECT ( COUNT( ?t ) AS ?textless ) WHERE {
          ?t cg:isStorySpotlight "Yes" ; cg:isTextless "Yes" .
        }
      }
    }
  }
  OPTIONAL {
    ?card cg:isStorySpotlight "Yes" ; cg:isTextless "Yes" .
    ?card cg:number ?id .
  }
}

SELECT ( COUNT( DISTINCT ?set ) AS ?count ) WHERE {
  ?set <http://cardgames.org/schema#block> "Commander" .
  ?f a <http://cardgames.org/schema#ForeignCardData> ; <http://cardgames.org/schema#language> "Portuguese (Brazil)" ; <http://cardgames.org/schema#forCard> ?card .
  ?card <http://cardgames.org/schema#forSet> ?set .
}

SELECT ?type ( SAMPLE( ?f ) AS ?exampleForeign ) WHERE {
  ?f a <http://cardgames.org/schema#ForeignCardData> ; <http://cardgames.org/schema#language> "German" ; <http://cardgames.org/schema#foreignType> ?type .
}
GROUP BY ?type
ORDER BY ?type

SELECT ( COUNT( DISTINCT ?card ) AS ?count ) WHERE {
  ?card <http://cardgames.org/schema#power> "Unknown" .
  ?card <http://cardgames.org/schema#text> ?text .
  FILTER ( CONTAINS( LCASE( STR( ?text ) ) , "triggered ability" ) )
}

SELECT ( COUNT( * ) AS ?count ) WHERE {
  {
    SELECT DISTINCT ?card ( COUNT( DISTINCT ?face ) AS ?faces ) WHERE {
      ?card <http://cardgames.org/schema#format> "premodern" .
      ?card <http://cardgames.org/schema#rulingText> "This is a triggered mana ability." .
      OPTIONAL {
        ?card <http://cardgames.org/schema#faceName> ?face .
      }
    }
    GROUP BY ?card
    HAVING ( COUNT( DISTINCT ?face ) <= 1 )
  }
}

SELECT DISTINCT ?lang WHERE {
  ?c <http://cardgames.org/schema#forSet> <http://cardgames.org/set/DIS> .
  ?f <http://cardgames.org/schema#forCard> ?c .
  ?f <http://cardgames.org/schema#language> ?lang .
}

PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?total ?without ?percentage WHERE {
  {
    SELECT ( COUNT( DISTINCT ?card ) AS ?total ) WHERE {
      ?card <http://cardgames.org/schema#uuid> ?uuid .
      ?leg rdf:type <http://cardgames.org/schema#Legality> ; <http://cardgames.org/schema#legalityUUID> ?uuid ; <http://cardgames.org/schema#format> "commander" ; <http://cardgames.org/schema#status> "Legal" .
    }
  }
  {
    SELECT ( COUNT( DISTINCT ?cardNoCW ) AS ?without ) WHERE {
      ?cardNoCW <http://cardgames.org/schema#uuid> ?uuid2 .
      ?leg2 rdf:type <http://cardgames.org/schema#Legality> ; <http://cardgames.org/schema#legalityUUID> ?uuid2 ; <http://cardgames.org/schema#format> "commander" ; <http://cardgames.org/schema#status> "Legal" .
      FILTER NOT EXISTS {
        ?cardNoCW <http://cardgames.org/schema#hasContentWarning> ?cw
      }
    }
  }
  BIND( ( xsd:decimal ( ?without ) * 100 ) / xsd:decimal ( ?total ) AS ?percentage )
}

PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?total ?french ?percent WHERE {
  {
    SELECT ( COUNT( DISTINCT ?card ) AS ?total ) WHERE {
      ?card rdf:type <http://cardgames.org/schema#Card> .
      ?card <http://cardgames.org/schema#power> ?pv .
      FILTER ( ! regex( str( ?pv ) , "^[0-9]+(\\.[0-9]+)?$" ) )
    }
  }
  {
    SELECT ( COUNT( DISTINCT ?cardF ) AS ?french ) WHERE {
      ?cardF rdf:type <http://cardgames.org/schema#Card> .
      ?cardF <http://cardgames.org/schema#power> ?pv2 .
      FILTER ( ! regex( str( ?pv2 ) , "^[0-9]+(\\.[0-9]+)?$" ) ) ?fdata <http://cardgames.org/schema#forCard> ?cardF .
      ?fdata <http://cardgames.org/schema#language> "French" .
    }
  }
  BIND( ( ?french * 100.0 ) / ?total AS ?percent )
}

SELECT ?foreign ?language WHERE {
  ?foreign <http://cardgames.org/schema#forCard> <http://cardgames.org/card/149934> .
  ?foreign <http://cardgames.org/schema#language> ?language .
}

PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX cg: <http://cardgames.org/schema#>
SELECT ?total ?normal ?notCount ( ?notCount / ?total AS ?proportion ) WHERE {
  {
    SELECT ( COUNT( DISTINCT ?card ) AS ?total ) WHERE {
      ?card rdf:type cg:Card .
    }
  }
  {
    SELECT ( COUNT( DISTINCT ?card2 ) AS ?normal ) WHERE {
      ?card2 rdf:type cg:Card ; cg:layout "normal" ; cg:text ?text .
    }
  }
  BIND( ?total - ?normal AS ?notCount ) FILTER ( ?total > 0 )
}

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT DISTINCT ?translation ?language ?label WHERE {
  ?translation a <http://cardgames.org/schema#SetTranslation> ; <http://cardgames.org/schema#setCode> "ARC" ; <http://cardgames.org/schema#language> ?language .
  OPTIONAL {
    ?translation rdfs:label ?label
  }
}
ORDER BY ?language

SELECT ?foreign ?language WHERE {
  ?foreign <http://cardgames.org/schema#foreignName> "A Pedra Fellwar" .
  ?foreign <http://cardgames.org/schema#language> ?language .
}

PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
PREFIX cg: <http://cardgames.org/schema#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?nameStr ?card ?cmc WHERE {
  VALUES ?nameStr {
    "Serra Angel" "Shrine Keeper"
  }
  {
    SELECT ?nameStr ( MAX( xsd:decimal ( ?cmcInner ) ) AS ?maxCmc ) WHERE {
      VALUES ?nameStr {
        "Serra Angel" "Shrine Keeper"
      }
      ?cardInner rdfs:label ?labelInner .
      FILTER ( STRSTARTS( LCASE( STR( ?labelInner ) ) , LCASE( ?nameStr ) ) ) ?cardInner cg:convertedManaCost ?cmcInner .
    }
    GROUP BY ?nameStr
  }
  ?card rdfs:label ?label .
  FILTER ( STRSTARTS( LCASE( STR( ?label ) ) , LCASE( ?nameStr ) ) ) ?card cg:convertedManaCost ?cmc .
  FILTER ( xsd:decimal ( ?cmc ) = ?maxCmc )
}
ORDER BY DESC ( xsd:decimal ( ?cmc ) )
LIMIT 1

PREFIX skos: <http://www.w3.org/2004/02/skos/core#>
PREFIX dc: <http://purl.org/dc/elements/1.1/>
PREFIX schema: <http://schema.org/>
PREFIX foaf: <http://xmlns.com/foaf/0.1/>
PREFIX dct: <http://purl.org/dc/terms/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?set ?itLabel ?anyLabel WHERE {
  <http://cardgames.org/card/24724> <http://cardgames.org/schema#forSet> ?set .
  OPTIONAL {
    VALUES ?pred {
      rdfs:label schema:name skos:prefLabel skos:altLabel foaf:name dct:title dc:title
    }
    ?set ?pred ?itLabel .
    FILTER ( lang( ?itLabel ) = "it" )
  }
  OPTIONAL {
    VALUES ?pred2 {
      rdfs:label schema:name skos:prefLabel skos:altLabel foaf:name dct:title dc:title
    }
    ?set ?pred2 ?anyLabel .
  }
}
LIMIT 10

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?set ?setLabel ( COUNT( DISTINCT ?foreign ) AS ?koreanCount ) ( IF( COUNT( DISTINCT ?foreign ) > 0 , true , false ) AS ?hasKorean ) WHERE {
  ?card rdfs:label ?cardLabel .
  FILTER ( regex( str( ?cardLabel ) , "Ancestor's Chosen" , "i" ) ) .
  ?card <http://cardgames.org/schema#forSet> ?set .
  OPTIONAL {
    ?foreign <http://cardgames.org/schema#language> "Korean" .
    ?foreign <http://cardgames.org/schema#forCard> ?card .
  }
  OPTIONAL {
    ?set rdfs:label ?setLabel .
  }
}
GROUP BY ?set ?setLabel
ORDER BY ?setLabel

SELECT ( COUNT( ?card ) AS ?count ) WHERE {
  ?card <http://cardgames.org/schema#forSet> <http://cardgames.org/set/10E> ; <http://cardgames.org/schema#artist> "Adam Rex" .
}

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
ASK {
  ?card rdfs:label "Angel of Mercy" @en ; <http://cardgames.org/schema#forSet> ?set .
  {
    ?set <http://cardgames.org/schema#mtgoCode> ?mtgoCode .
  } UNION {
    ?set <http://cardgames.org/schema#mtgoId> ?mtgoId .
  } UNION {
    ?set <http://cardgames.org/schema#isOnlineOnly> ?isOnlineOnly .
