  }
}

SELECT ( COUNT( DISTINCT ?set ) AS ?count ) WHERE {
  ?set <http://cardgames.org/schema#block> "Ice Age" .
  ?st <http://cardgames.org/schema#forSet> ?set .
  ?st <http://cardgames.org/schema#language> "Italian" .
}

PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?code ?set ?setLabel ?foreignOnly WHERE {
  VALUES ?code {
    "C14" "C18" "CSP" "MMA" "PLIST"
  }
  ?set rdf:type <http://cardgames.org/schema#Set> .
  ?set rdfs:label ?setLabel .
  FILTER ( CONTAINS( STR( ?setLabel ) , CONCAT ( "(" , ?code , ")" ) ) ) .
  OPTIONAL {
    ?set <http://cardgames.org/schema#foreignOnly> ?foreignOnly
  }
  .
}
ORDER BY ?code ?setLabel

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT DISTINCT ?artist ?card ?cardLabel WHERE {
  ?card <http://cardgames.org/schema#forSet> <http://cardgames.org/set/CSP> .
  ?card <http://cardgames.org/schema#artist> ?artist .
  FILTER ( regex( str( ?artist ) , "Jeremy Jarvis" , "i" ) || regex( str( ?artist ) , "Aaron Miller" , "i" ) || regex( str( ?artist ) , "^Chippy$" , "i" ) ) OPTIONAL {
    ?card rdfs:label ?cardLabel
  }
}
ORDER BY ?artist ?cardLabel

SELECT ( COUNT( DISTINCT ?card ) AS ?highCMC ) ( COUNT( DISTINCT ?unknownCard ) AS ?unknownPower ) WHERE {
  ?card <http://cardgames.org/schema#setCode> "CSP" .
  ?card <http://cardgames.org/schema#convertedManaCost> ?cmc .
  FILTER ( ?cmc > 5 ) .
  OPTIONAL {
    ?card <http://cardgames.org/schema#power> ?pw .
    FILTER ( STR( ?pw ) = "Unknown" ) .
    BIND( ?card AS ?unknownCard )
  }
}

PREFIX cg: <http://cardgames.org/schema#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?card ?label ?setCode ?flavor WHERE {
  ?card rdfs:label ?label .
  FILTER ( CONTAINS( LCASE( STR( ?label ) ) , "ancestor's chosen" ) ) .
  ?card cg:flavorText ?flavor .
  FILTER ( langMatches( lang( ?flavor ) , "it" ) ) .
  OPTIONAL {
    ?card cg:setCode ?setCode
  }
}

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?card ?cardLabel ?foreign ?foreignText WHERE {
  ?card <http://cardgames.org/schema#setCode> "CSP" .
  OPTIONAL {
    ?card rdfs:label ?cardLabel
  }
  ?foreign <http://cardgames.org/schema#forCard> ?card ; <http://cardgames.org/schema#language> "Italian" ; <http://cardgames.org/schema#foreignText> ?foreignText .
}
ORDER BY ?cardLabel

SELECT ?card ?italianName WHERE {
  ?card <http://cardgames.org/schema#forSet> <http://cardgames.org/set/CSP> .
  ?card <http://cardgames.org/schema#convertedManaCost> ?cmc .
  {
    SELECT ( MAX( ?cmc2 ) AS ?maxCmc ) WHERE {
      ?c2 <http://cardgames.org/schema#forSet> <http://cardgames.org/set/CSP> .
      ?c2 <http://cardgames.org/schema#convertedManaCost> ?cmc2 .
    }
  }
  FILTER ( ?cmc = ?maxCmc ) OPTIONAL {
    ?f <http://cardgames.org/schema#forCard> ?card .
    ?f <http://cardgames.org/schema#language> "Italian" .
    ?f <http://cardgames.org/schema#foreignName> ?italianName .
  }
}
ORDER BY ?card

PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ( COUNT( ?card ) AS ?total ) ( SUM( ?is7 ) AS ?count7 ) ( ( xsd:decimal ( SUM( ?is7 ) ) / xsd:decimal ( COUNT( ?card ) ) ) * 100 AS ?percentage ) WHERE {
  ?card <http://cardgames.org/schema#setCode> "CSP" .
  BIND( IF( EXISTS {
    ?card <http://cardgames.org/schema#convertedManaCost> ?cmc .
    FILTER ( xsd:decimal ( ?cmc ) = 7 )
  }
  , 1 , 0 ) AS ?is7 )
}

PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?set ?setLabel ( COUNT( DISTINCT ?card ) AS ?totalCards ) ( COUNT( DISTINCT ?powerfulCard ) AS ?powerfulCards ) ( ( COUNT( DISTINCT ?powerfulCard ) * 100.0 ) / COUNT( DISTINCT ?card ) AS ?percentage ) WHERE {
  BIND( <http://cardgames.org/set/CSP> AS ?set ) OPTIONAL {
    ?set rdfs:label ?setLabel
  }
  ?card a <http://cardgames.org/schema#Card> ; <http://cardgames.org/schema#forSet> ?set .
  OPTIONAL {
    ?card <http://cardgames.org/schema#power> ?power .
    FILTER ( regex( str( ?power ) , "^[0-9]+$" ) ) BIND( xsd:integer ( ?power ) AS ?pval ) FILTER ( ?pval >= 8 ) BIND( ?card AS ?powerfulCard )
  }
}
GROUP BY ?set ?setLabel
ORDER BY ?setLabel
LIMIT 1

PREFIX cg: <http://cardgames.org/schema#>
SELECT ?format ?card ?cardName WHERE {
  {
    SELECT ?topFormat WHERE {
      ?x cg:status "Banned" ; cg:format ?topFormat .
    }
    GROUP BY ?topFormat
    ORDER BY DESC ( COUNT( ?x ) )
    LIMIT 1
  }
  BIND( ?topFormat AS ?format ) ?legality cg:status "Banned" ; cg:format ?format ; cg:legalityUUID ?lu .
  ?card cg:uuid ?lu .
  OPTIONAL {
    ?card cg:cardName ?cardName
  }
}
ORDER BY ?cardName

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ( SAMPLE( ?card ) AS ?cardSample ) ( SAMPLE( ?cardLabel ) AS ?cardLabelSample ) ( GROUP_CONCAT( DISTINCT ?format ; separator = ", " ) AS ?bannedFormats ) WHERE {
  ?card <http://cardgames.org/schema#edhrecRank> 1 .
  OPTIONAL {
    ?card rdfs:label ?cardLabel .
  }
  OPTIONAL {
    ?card ?p ?legality .
    ?legality a <http://cardgames.org/schema#Legality> ; <http://cardgames.org/schema#status> "Banned" ; <http://cardgames.org/schema#format> ?format .
  }
  OPTIONAL {
    ?card <http://cardgames.org/schema#scryfallOracleId> ?oracleId
  }
}
GROUP BY ?oracleId
ORDER BY ?cardLabelSample

SELECT DISTINCT ?set ?koName ?engName WHERE {
  ?stko a <http://cardgames.org/schema#SetTranslation> ; <http://cardgames.org/schema#language> "Korean" ; <http://cardgames.org/schema#forSet> ?set .
  OPTIONAL {
    ?stko <http://cardgames.org/schema#translationText> ?koName .
  }
  OPTIONAL {
    ?steng a <http://cardgames.org/schema#SetTranslation> ; <http://cardgames.org/schema#forSet> ?set ; <http://cardgames.org/schema#language> "English" ; <http://cardgames.org/schema#translationText> ?engName .
  }
  FILTER NOT EXISTS {
    ?stja a <http://cardgames.org/schema#SetTranslation> ; <http://cardgames.org/schema#forSet> ?set ; <http://cardgames.org/schema#language> "Japanese" .
  }
}
ORDER BY ?engName ?koName

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?bondType ( COUNT( ?bond ) AS ?count ) ?bondTypeLabel WHERE {
  ?bond a <http://toxkg.org/schema#Bond> ; <http://toxkg.org/schema#bondType> ?bondType .
  OPTIONAL {
    ?bondType rdfs:label ?bondTypeLabel .
  }
}
GROUP BY ?bondType ?bondTypeLabel
ORDER BY DESC ( ?count )
LIMIT 1

SELECT ( AVG( ?oCount ) AS ?avgO ) WHERE {
  {
    SELECT ?mol ( COUNT( DISTINCT ?atom ) AS ?oCount ) WHERE {
      ?b0 <http://toxkg.org/schema#partOfMolecule> ?mol .
      FILTER NOT EXISTS {
        ?b <http://toxkg.org/schema#partOfMolecule> ?mol ; <http://toxkg.org/schema#bondType> ?bt .
        FILTER ( str( ?bt ) != "-" )
      }
      OPTIONAL {
        ?atom <http://toxkg.org/schema#partOfMolecule> ?mol ; <http://toxkg.org/schema#element> "Oxygen" .
      }
    }
    GROUP BY ?mol
  }
}

PREFIX tox: <http://toxkg.org/schema#>
SELECT ( AVG( ?singleCount ) AS ?avgSingleBonds ) WHERE {
  {
    SELECT ?mol ( COUNT( DISTINCT ?bond ) AS ?singleCount ) WHERE {
      ?mol tox:hasCarcinogenicity "Carcinogenic" .
      OPTIONAL {
        ?bond tox:bondType "-" ; tox:connectsAtom ?atom .
        ?atom tox:partOfMolecule ?mol .
      }
    }
    GROUP BY ?mol
  }
}

PREFIX tox: <http://toxkg.org/schema#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT DISTINCT ?molecule ?moleculeLabel WHERE {
  ?molecule tox:hasCarcinogenicity "Carcinogenic" .
  ?bond tox:partOfMolecule ?molecule .
  ?bond tox:bondType "#" .
  OPTIONAL {
    ?molecule rdfs:label ?moleculeLabel
  }
}
ORDER BY ?molecule

PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?molecule ?moleculeLabel ( ( SUM( IF( ?elem = "Carbon" , ?atomMass , 0 ) ) / SUM( ?atomMass ) ) * 100 AS ?percentC ) WHERE {
  ?bond rdf:type <http://toxkg.org/schema#Bond> ; <http://toxkg.org/schema#bondType> "=" ; <http://toxkg.org/schema#partOfMolecule> ?molecule .
  ?atom <http://toxkg.org/schema#partOfMolecule> ?molecule ; <http://toxkg.org/schema#element> ?elem .
  BIND( IF( ?elem = "Hydrogen" , 1.00794 , IF( ?elem = "Carbon" , 12.011 , IF( ?elem = "Nitrogen" , 14.007 , IF( ?elem = "Oxygen" , 15.999 , IF( ?elem = "Sulfur" , 32.06 , IF( ?elem = "Chlorine" , 35.45 , IF( ?elem = "Bromine" , 79.904 , IF( ?elem = "Fluorine" , 18.998 , IF( ?elem = "Phosphorus" , 30.974 , 0 ) ) ) ) ) ) ) ) ) AS ?atomMass ) OPTIONAL {
    ?molecule rdfs:label ?moleculeLabel
  }
}
GROUP BY ?molecule ?moleculeLabel
HAVING ( SUM( ?atomMass ) > 0 )
ORDER BY DESC ( ?percentC )
LIMIT 100

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?atom ?atomLabel ?element WHERE {
  VALUES ?bond {
    <http://toxkg.org/bond/TR004_8_9>
  }
  ?bond <http://toxkg.org/schema#connectsAtom> ?atom .
  OPTIONAL {
    ?atom rdfs:label ?atomLabel .
  }
  OPTIONAL {
    ?atom <http://toxkg.org/schema#element> ?element .
  }
}
ORDER BY ?atom

SELECT DISTINCT ?element WHERE {
  ?bond <http://toxkg.org/schema#bondType> "=" .
  ?bond <http://toxkg.org/schema#connectsAtom> ?atom .
  ?atom <http://toxkg.org/schema#element> ?element .
}
ORDER BY ?element

SELECT ?bond ?bondType WHERE {
  BIND( <http://toxkg.org/bond/TR004_8_20> AS ?bond ) ?bond <http://toxkg.org/schema#bondType> ?bondType .
}

PREFIX tox: <http://toxkg.org/schema#>
SELECT ?element ( COUNT( DISTINCT ?atom ) AS ?count ) WHERE {
  ?atom tox:partOfMolecule ?m ; tox:element ?element .
  FILTER ( ?element IN ( "Iodine" , "Sulfur" ) ) FILTER EXISTS {
    ?bond tox:partOfMolecule ?m ; tox:bondType "-" .
  }
  FILTER NOT EXISTS {
    ?badBond tox:partOfMolecule ?m ; tox:bondType ?badType .
    FILTER ( ?badType != "-" )
  }
}
GROUP BY ?element
ORDER BY ?element

PREFIX tox: <http://toxkg.org/schema#>
SELECT ?total ?withF ( ( ?total - ?withF ) * 100.0 / ?total AS ?percent_without_f ) WHERE {
  {
    SELECT ( COUNT( DISTINCT ?mol ) AS ?total ) WHERE {
      ?mol tox:hasCarcinogenicity "Carcinogenic" .
    }
  }
  {
    SELECT ( COUNT( DISTINCT ?molF ) AS ?withF ) WHERE {
      ?molF tox:hasCarcinogenicity "Carcinogenic" .
      ?atom tox:partOfMolecule ?molF .
      ?atom tox:element "Fluorine" .
    }
  }
}

SELECT ( COUNT( DISTINCT ?molecule ) AS ?total ) ( COUNT( DISTINCT ?carcMol ) AS ?carc ) ( ( COUNT( DISTINCT ?carcMol ) * 100.0 ) / COUNT( DISTINCT ?molecule ) AS ?percentage ) WHERE {
  ?bond <http://toxkg.org/schema#bondType> "#" .
  ?bond <http://toxkg.org/schema#partOfMolecule> ?molecule .
  OPTIONAL {
    ?molecule <http://toxkg.org/schema#hasCarcinogenicity> "Carcinogenic" .
    BIND( ?molecule AS ?carcMol )
  }
}

SELECT ?percentFormatted ?doubleCount ?total WHERE {
  {
    SELECT ( COUNT( ?bond ) AS ?total ) ( COUNT( ?db ) AS ?doubleCount ) WHERE {
      ?bond a <http://toxkg.org/schema#Bond> ; <http://toxkg.org/schema#partOfMolecule> <http://toxkg.org/molecule/TR008> ; <http://toxkg.org/schema#bondType> ?type .
      OPTIONAL {
        ?bond <http://toxkg.org/schema#bondType> "=" .
        BIND( ?bond AS ?db )
      }
    }
  }
  BIND( ( ?doubleCount * 100.0 ) / ?total AS ?percent ) BIND( ROUND( ?percent * 100000 ) AS ?roundedInt ) BIND( FLOOR( ?roundedInt / 100000 ) AS ?integerPart ) BIND( ( ?roundedInt - ( ?integerPart * 100000 ) ) AS ?fractionalInt ) BIND( CONCAT ( "00000" , STR( ?fractionalInt ) ) AS ?fracPad ) BIND( SUBSTR( ?fracPad , STRLEN( ?fracPad ) - 4 , 5 ) AS ?fractionalStr ) BIND( CONCAT ( STR( ?integerPart ) , "." , ?fractionalStr , "%" ) AS ?percentFormatted )
}

PREFIX tox: <http://toxkg.org/schema#>
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?total ?carcinogenic ?percentage ?percentageRounded ?percentageStr WHERE {
  {
    SELECT ( COUNT( ?m ) AS ?total ) ( SUM( IF( BOUND( ?status ) && ?status = "Carcinogenic" , 1 , 0 ) ) AS ?carcinogenic ) WHERE {
      ?m rdf:type tox:Molecule .
      OPTIONAL {
        ?m tox:hasCarcinogenicity ?status .
      }
    }
  }
  BIND( ( ?carcinogenic * 100.0 ) / ?total AS ?percentage ) BIND( ROUND( ?percentage * 1000 ) AS ?perc_milli_int ) BIND( ( ?perc_milli_int / 1000.0 ) AS ?percentageRounded ) BIND( STR( ?perc_milli_int ) AS ?perc_int_str ) BIND( STR( FLOOR( ?perc_milli_int / 1000 ) ) AS ?whole_str ) BIND( STR( ?perc_milli_int - ( FLOOR( ?perc_milli_int / 1000 ) * 1000 ) ) AS ?rem_int_str ) BIND( IF( STRLEN( ?rem_int_str ) = 1 , CONCAT ( "00" , ?rem_int_str ) , IF( STRLEN( ?rem_int_str ) = 2 , CONCAT ( "0" , ?rem_int_str ) , ?rem_int_str ) ) AS ?rem3 ) BIND( CONCAT ( ?whole_str , "." , ?rem3 , "%" ) AS ?percentageStr )
}

PREFIX tox: <http://toxkg.org/schema#>
SELECT ?explicit ?implicit ?total ?percent4 WHERE {
  {
    SELECT ( COUNT( ?h ) AS ?explicit ) WHERE {
      ?h tox:partOfMolecule <http://toxkg.org/molecule/TR206> ; tox:element "Hydrogen" .
    }
  }
  {
    SELECT ( SUM( ?impH ) AS ?implicit ) WHERE {
      ?atom tox:partOfMolecule <http://toxkg.org/molecule/TR206> ; tox:element ?elem .
      FILTER ( ?elem != "Hydrogen" ) BIND( IF( ?elem = "Carbon" , 4 , IF( ?elem = "Nitrogen" , 3 , IF( ?elem = "Oxygen" , 2 , IF( ?elem = "Sulfur" , 2 , IF( ?elem = "Phosphorus" , 3 , IF( ?elem = "Bromine" , 1 , IF( ?elem = "Chlorine" , 1 , IF( ?elem = "Fluorine" , 1 , 0 ) ) ) ) ) ) ) ) AS ?valence ) {
        SELECT ?atom ( SUM( ?order ) AS ?sumOrder ) WHERE {
          ?bond tox:partOfMolecule <http://toxkg.org/molecule/TR206> ; tox:connectsAtom ?atom ; tox:bondType ?bt .
          BIND( IF( ?bt = "-" , 1 , IF( ?bt = "=" , 2 , IF( ?bt = "#" , 3 , 1 ) ) ) AS ?order )
        }
        GROUP BY ?atom
      }
      BIND( IF( ( ?valence - ?sumOrder ) > 0 , ( ?valence - ?sumOrder ) , 0 ) AS ?impH )
    }
  }
  BIND( ( ?explicit + ?implicit ) AS ?total ) BIND( IF( ?total = 0 , 0.0 , ( ?explicit * 100.0 ) / ?total ) AS ?percent ) BIND( ( ROUND( ?percent * 10000.0 ) / 10000.0 ) AS ?percent4 )
}

