PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX schema: <http://schema.org/>
SELECT ( COUNT( DISTINCT ?district ) AS ?count ) WHERE {
  {
    ?district rdf:type schema:District .
    ?district schema:averageFemaleSalary ?val .
    FILTER ( xsd:decimal ( ?val ) > 6000 && xsd:decimal ( ?val ) < 10000 )
  } UNION {
    ?district rdf:type schema:District .
    ?district schema:femaleAverageSalary ?val .
    FILTER ( xsd:decimal ( ?val ) > 6000 && xsd:decimal ( ?val ) < 10000 )
  } UNION {
    ?district rdf:type schema:District .
    ?district schema:averageSalaryFemale ?val .
    FILTER ( xsd:decimal ( ?val ) > 6000 && xsd:decimal ( ?val ) < 10000 )
  } UNION {
    ?district rdf:type schema:District .
    ?district schema:averageSalary ?val .
    ?district schema:gender ?g .
    FILTER ( lcase( str( ?g ) ) = "female" ) FILTER ( xsd:decimal ( ?val ) > 6000 && xsd:decimal ( ?val ) < 10000 )
  } UNION {
    ?measure schema:gender ?g .
    FILTER ( lcase( str( ?g ) ) = "female" ) {
      ?measure schema:averageSalary ?val .
    } UNION {
      ?measure schema:amount ?val .
    }
    ?measure ?link ?district .
    FILTER ( ?link IN ( schema:district , schema:region , schema:livesInDistrict ) ) ?district rdf:type schema:District .
    FILTER ( xsd:decimal ( ?val ) > 6000 && xsd:decimal ( ?val ) < 10000 )
  }
}

PREFIX fn: <http://financialdb.org/schema#>
SELECT ?lowestDistrict ?lowestAvg ?highestAvg ?gap ( GROUP_CONCAT( DISTINCT STR( ?oldAccId ) ; separator = ", " ) AS ?oldestAccounts ) ( GROUP_CONCAT( DISTINCT STR( ?lowAccId ) ; separator = ", " ) AS ?lowestDistrictAccounts ) WHERE {
  {
    SELECT ( MIN( ?bd ) AS ?oldestBirthDate ) WHERE {
      ?c a fn:Client ; fn:gender "Female" ; fn:birthDate ?bd .
    }
  }
  {
    SELECT ( MIN( ?avg ) AS ?minAvgFemaleDistrict ) WHERE {
      ?c2 a fn:Client ; fn:gender "Female" ; fn:livesInDistrict ?d2 .
      ?d2 fn:averageSalary ?avg .
    }
  }
  {
    SELECT ( MAX( ?avgAll ) AS ?maxAvg ) WHERE {
      ?dAll fn:averageSalary ?avgAll .
    }
  }
  ?lowestDistrict fn:averageSalary ?minAvgFemaleDistrict .
  BIND( ?minAvgFemaleDistrict AS ?lowestAvg ) BIND( ?maxAvg AS ?highestAvg ) BIND( ( ?maxAvg - ?minAvgFemaleDistrict ) AS ?gap ) ?old a fn:Client ; fn:gender "Female" ; fn:birthDate ?oldestBirthDate .
  ?dispOld fn:forClient ?old ; fn:forAccount ?oldAcc .
  ?oldAcc fn:accountId ?oldAccId .
  ?c3 a fn:Client ; fn:gender "Female" ; fn:livesInDistrict ?lowestDistrict .
  ?dispL fn:forClient ?c3 ; fn:forAccount ?lowAcc .
  ?lowAcc fn:accountId ?lowAccId .
}
GROUP BY ?lowestDistrict ?lowestAvg ?highestAvg ?gap

PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?account ?accountId ?client WHERE {
  ?client rdf:type <http://financialdb.org/schema#Client> ; <http://financialdb.org/schema#birthDate> ?birth ; <http://financialdb.org/schema#livesInDistrict> ?district .
