      ?c rdf:type <http://financialdb.org/schema#Client> ; <http://financialdb.org/schema#birthDate> ?b .
    }
  }
  {
    SELECT ( MAX( ?a ) AS ?maxAvg ) WHERE {
      ?d <http://financialdb.org/schema#averageSalary> ?a .
