  }
  FILTER ( ?birth = ?maxBirth ) FILTER ( ?avg = ?maxAvg )
}

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT DISTINCT ?account ?accountLabel ?loan ?loanAmount WHERE {
