  ?loan <http://financialdb.org/schema#loanAmount> ?loanAmount .
  ?account <http://financialdb.org/schema#frequencyLabel> ?freq .
  FILTER ( lcase( str( ?freq ) ) = "weekly" ) .
  {
    SELECT ( MIN( ?amt ) AS ?minAmt ) WHERE {
      ?card2 <http://financialdb.org/schema#issuedDate> ?date2 .
