      ?card2 <http://financialdb.org/schema#linkedToDisposition> ?disp2 .
      ?disp2 <http://financialdb.org/schema#forAccount> ?acc2 .
      ?loan2 <http://financialdb.org/schema#belongsToAccount> ?acc2 .
      ?loan2 <http://financialdb.org/schema#loanAmount> ?amt .
    }
  }
  FILTER ( ?loanAmount = ?minAmt ) OPTIONAL {
