  }
}
ORDER BY ?account

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX schema: <http://schema.org/>
SELECT DISTINCT ?account ?accountLabel ?loan ?loanAmount ?createdOn WHERE {
