      ?l a schema:Loan ; schema:loanDuration ?ld ; schema:loanAmount ?la ; schema:belongsToAccount ?acc .
      ?acc schema:createdOn ?co .
      FILTER ( ?ld > 12 ) FILTER ( STRSTARTS( STR( ?co ) , "1993" ) )
    }
  }
  FILTER ( ?loanAmount = ?maxAmt )
}
