  ?client a <http://financialdb.org/schema#Client> ; <http://financialdb.org/schema#birthDate> "1976-01-29" ^^ xsd:date ; <http://financialdb.org/schema#gender> "Female" .
  ?disp a <http://financialdb.org/schema#Disposition> ; <http://financialdb.org/schema#forClient> ?client ; <http://financialdb.org/schema#forAccount> ?account .
