PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?district ?maleCount ?totalCount ?malePercent WHERE {
  BIND( <http://financialdb.org/district/14> as ?district ) {
    SELECT ( COUNT( DISTINCT ?client ) as ?totalCount ) WHERE {
      ?disp <http://financialdb.org/schema#forAccount> ?acct .
      ?acct <http://financialdb.org/schema#belongsToDistrict> ?district .
      ?disp <http://financialdb.org/schema#forClient> ?client .
    }
  }
  {
    SELECT ( COUNT( DISTINCT ?clientM ) as ?maleCount ) WHERE {
      ?disp2 <http://financialdb.org/schema#forAccount> ?acct2 .
      ?acct2 <http://financialdb.org/schema#belongsToDistrict> ?district .
      ?disp2 <http://financialdb.org/schema#forClient> ?clientM .
      ?clientM <http://financialdb.org/schema#gender> "Male" .
    }
  }
  BIND( xsd:decimal ( ?maleCount ) / xsd:decimal ( ?totalCount ) * 100 as ?malePercent )
}

PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?client ?account ?loan ?bal_1993_03_22 ?bal_1998_12_27 ?increaseRate WHERE {
  {
    SELECT ( MIN( ?txId ) AS ?minTxId ) WHERE {
      ?loan <http://financialdb.org/schema#belongsToAccount> ?acc .
      ?tx <http://financialdb.org/schema#forAccount> ?acc ; <http://financialdb.org/schema#transactionDate> "1993-07-05" ^^ xsd:date ; <http://financialdb.org/schema#transactionId> ?txId .
    }
  }
  ?txMin <http://financialdb.org/schema#transactionId> ?minTxId ; <http://financialdb.org/schema#forAccount> ?account .
  ?loan <http://financialdb.org/schema#belongsToAccount> ?account .
  ?disp <http://financialdb.org/schema#forAccount> ?account ; <http://financialdb.org/schema#forClient> ?client .
  {
    SELECT ?account ( MAX( ?d1 ) AS ?maxd1 ) WHERE {
      ?tx1 <http://financialdb.org/schema#forAccount> ?account ; <http://financialdb.org/schema#transactionDate> ?d1 .
      FILTER ( ?d1 <= "1993-03-22" ^^ xsd:date )
    }
    GROUP BY ?account
  }
  ?txA <http://financialdb.org/schema#forAccount> ?account ; <http://financialdb.org/schema#transactionDate> ?dateA ; <http://financialdb.org/schema#balanceAfter> ?bal_1993_03_22 .
  FILTER ( ?dateA = ?maxd1 ) {
    SELECT ?account ( MAX( ?d2 ) AS ?maxd2 ) WHERE {
      ?tx2 <http://financialdb.org/schema#forAccount> ?account ; <http://financialdb.org/schema#transactionDate> ?d2 .
      FILTER ( ?d2 <= "1998-12-27" ^^ xsd:date )
    }
    GROUP BY ?account
  }
  ?txB <http://financialdb.org/schema#forAccount> ?account ; <http://financialdb.org/schema#transactionDate> ?dateB ; <http://financialdb.org/schema#balanceAfter> ?bal_1998_12_27 .
  FILTER ( ?dateB = ?maxd2 ) BIND( ( ?bal_1998_12_27 - ?bal_1993_03_22 ) AS ?diff ) BIND( ( ?diff / ?bal_1993_03_22 ) AS ?increaseRate )
}
LIMIT 1

SELECT ?loanClass ?statusProp ( IF( ?sumTotal > 0 , ( 100.0 * ?sumPaid / ?sumTotal ) , 0 ) AS ?percentage ) WHERE {
  BIND( <http://financialdb.org/schema#Loan> AS ?loanClass ) BIND( <http://financialdb.org/schema#status> AS ?statusProp ) {
    SELECT ( SUM( ?amtTotal ) AS ?sumTotal ) WHERE {
      ?ln a ?loanClass .
      ?ln <http://financialdb.org/schema#loanAmount> ?amtTotal .
    }
  }
  {
    SELECT ( SUM( ?amtPaid ) AS ?sumPaid ) WHERE {
      ?ln2 a ?loanClass .
      ?ln2 <http://financialdb.org/schema#loanAmount> ?amtPaid .
      ?ln2 ?statusProp "A" .
    }
  }
}

SELECT ( ( SUM( IF( ?status = "A" , 1 , 0 ) ) * 100.0 ) / COUNT( ?loan ) AS ?percentage ) ( COUNT( ?loan ) AS ?totalLoans ) ( SUM( IF( ?status = "A" , 1 , 0 ) ) AS ?loansWithA ) WHERE {
  ?loan a <http://financialdb.org/schema#Loan> ; <http://financialdb.org/schema#loanAmount> ?amount ; <http://financialdb.org/schema#status> ?status .
  FILTER ( ?amount < 100000 )
}

PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT DISTINCT ?district ?districtLabel ?state ?stateLabel ?rate1995 ?rate1996 ?pctInc WHERE {
  ?loan a <http://financialdb.org/schema#Loan> .
  ?loan <http://financialdb.org/schema#status> "A" .
  ?loan <http://financialdb.org/schema#belongsToAccount> ?acc .
  ?disp <http://financialdb.org/schema#forAccount> ?acc .
  ?disp <http://financialdb.org/schema#forClient> ?client .
  ?client <http://financialdb.org/schema#livesInDistrict> ?district .
  ?district <http://financialdb.org/schema#unemploymentRate1995> ?rate1995 .
  ?district <http://financialdb.org/schema#unemploymentRate1996> ?rate1996 .
  OPTIONAL {
    ?district rdfs:label ?districtLabel
  }
  OPTIONAL {
    ?district <http://financialdb.org/schema#belongsToState> ?state .
    OPTIONAL {
      ?state rdfs:label ?stateLabel
    }
  }
  FILTER ( xsd:decimal ( ?rate1995 ) > 0 ) BIND( ( ( xsd:decimal ( ?rate1996 ) - xsd:decimal ( ?rate1995 ) ) / xsd:decimal ( ?rate1995 ) ) * 100 AS ?pctInc )
}
ORDER BY ?district

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?district ?districtLabel ( SUM( ?amount ) AS ?totalAmount ) WHERE {
  ?t a <http://financialdb.org/schema#Transaction> ; <http://financialdb.org/schema#transactionTypeLabel> "Withdrawal" ; <http://financialdb.org/schema#transactionDate> ?date ; <http://financialdb.org/schema#transactionAmount> ?amount ; <http://financialdb.org/schema#forAccount> ?acc .
  ?acc <http://financialdb.org/schema#belongsToDistrict> ?district .
  ?district rdfs:label ?districtLabel .
  FILTER ( STRSTARTS( STR( ?date ) , "1996-01" ) ) FILTER NOT EXISTS {
    ?card a <http://financialdb.org/schema#Card> ; <http://financialdb.org/schema#cardType> "credit" ; <http://financialdb.org/schema#linkedToDisposition> ?disp .
    ?disp <http://financialdb.org/schema#forAccount> ?acc .
  }
}
GROUP BY ?district ?districtLabel
ORDER BY DESC ( ?totalAmount )
LIMIT 10

