PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ( AVG( ?crimeNum ) AS ?avgCrime ) WHERE {
  {
    SELECT DISTINCT ?region ?crimeNum WHERE {
      ?region <http://financialdb.org/schema#crimeRate1995> ?crimeVal .
      BIND( xsd:decimal ( ?crimeVal ) AS ?crimeNum ) FILTER ( ?crimeNum > 4000 ) ?account a <http://financialdb.org/schema#Account> ; <http://financialdb.org/schema#belongsToDistrict> ?region ; <http://financialdb.org/schema#createdOn> ?created .
      FILTER ( ?created >= "1997-01-01" ^^ xsd:date )
    }
  }
}

SELECT ?tx ?txId ?txAmount ?txDate ?txTypeLabel ?txPurposeLabel ?account ?disposition WHERE {
  ?disposition <http://financialdb.org/schema#forClient> <http://financialdb.org/client/3356> .
  ?disposition <http://financialdb.org/schema#forAccount> ?account .
  ?tx <http://financialdb.org/schema#forAccount> ?account .
  ?tx <http://financialdb.org/schema#transactionTypeRaw> "VYDAJ" .
  FILTER NOT EXISTS {
    ?tx <http://financialdb.org/schema#toAccount> ?to
  }
  FILTER NOT EXISTS {
    ?tx <http://financialdb.org/schema#recipientAccount> ?rec
  }
  OPTIONAL {
    ?tx <http://financialdb.org/schema#transactionId> ?txId
  }
  OPTIONAL {
    ?tx <http://financialdb.org/schema#transactionAmount> ?txAmount
  }
  OPTIONAL {
    ?tx <http://financialdb.org/schema#transactionDate> ?txDate
  }
  OPTIONAL {
    ?tx <http://financialdb.org/schema#transactionTypeLabel> ?txTypeLabel
  }
  OPTIONAL {
    ?tx <http://financialdb.org/schema#transactionPurposeLabel> ?txPurposeLabel
  }
}
ORDER BY ?txDate

PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ( ?female * 100.0 / ?total AS ?percent ) WHERE {
  {
    SELECT ( COUNT( DISTINCT ?client ) AS ?total ) WHERE {
      ?disp <http://financialdb.org/schema#forClient> ?client ; <http://financialdb.org/schema#forAccount> ?account .
      ?account <http://financialdb.org/schema#belongsToDistrict> ?district .
      ?district <http://financialdb.org/schema#averageSalary> ?avgSalary .
      FILTER ( xsd:decimal ( ?avgSalary ) > 10000 )
    }
  }
  {
    SELECT ( COUNT( DISTINCT ?client2 ) AS ?female ) WHERE {
      ?disp2 <http://financialdb.org/schema#forClient> ?client2 ; <http://financialdb.org/schema#forAccount> ?account2 .
      ?account2 <http://financialdb.org/schema#belongsToDistrict> ?district2 .
      ?district2 <http://financialdb.org/schema#averageSalary> ?avgSalary2 .
      FILTER ( xsd:decimal ( ?avgSalary2 ) > 10000 ) ?client2 <http://financialdb.org/schema#gender> ?gender2 .
      FILTER ( lcase( str( ?gender2 ) ) = "female" )
    }
  }
}

PREFIX schema: <http://schema.org/>
SELECT ?sum1996 ?sum1997 ?growth WHERE {
  {
    SELECT ( SUM( ?loanAmount ) AS ?sum1996 ) WHERE {
      ?loan a schema:Loan ; schema:loanAmount ?loanAmount ; schema:belongsToAccount ?acct .
      ?acct schema:createdOn ?createdOn .
      FILTER ( STRSTARTS( STR( ?createdOn ) , "1996" ) ) ?disp schema:forAccount ?acct ; schema:forClient ?client .
      ?client schema:gender "Male" .
    }
  }
  {
    SELECT ( SUM( ?loanAmount2 ) AS ?sum1997 ) WHERE {
      ?loan2 a schema:Loan ; schema:loanAmount ?loanAmount2 ; schema:belongsToAccount ?acct2 .
      ?acct2 schema:createdOn ?createdOn2 .
      FILTER ( STRSTARTS( STR( ?createdOn2 ) , "1997" ) ) ?disp2 schema:forAccount ?acct2 ; schema:forClient ?client2 .
      ?client2 schema:gender "Male" .
    }
  }
  BIND( ( ?sum1997 - ?sum1996 ) / ?sum1996 AS ?growth )
}

PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?account ?freqLabel ?freqRaw ?debitPurpose WHERE {
  BIND( <http://financialdb.org/account/3> AS ?account ) .
  OPTIONAL {
    ?account <http://financialdb.org/schema#frequencyLabel> ?freqLabel
  }
  .
  OPTIONAL {
    ?account <http://financialdb.org/schema#frequencyRaw> ?freqRaw
  }
  .
  {
    SELECT DISTINCT ?debitPurpose WHERE {
      ?tx rdf:type <http://financialdb.org/schema#Transaction> .
      ?tx <http://financialdb.org/schema#transactionAmount> 3539 .
      ?tx <http://financialdb.org/schema#transactionTypeLabel> "Withdrawal" .
      OPTIONAL {
        ?tx <http://financialdb.org/schema#transactionPurposeLabel> ?debitPurpose
      }
      .
    }
  }
}

PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX fin: <http://financialdb.org/schema#>
SELECT ?maleCount ?maleWeeklyCount ( ( ?maleWeeklyCount * 100.0 ) / ?maleCount AS ?percentage ) WHERE {
  {
    SELECT ( COUNT( DISTINCT ?client ) AS ?maleCount ) WHERE {
      ?client rdf:type fin:Client ; fin:gender "Male" .
    }
  }
  {
    SELECT ( COUNT( DISTINCT ?client ) AS ?maleWeeklyCount ) WHERE {
      ?client rdf:type fin:Client ; fin:gender "Male" .
      ?disp fin:forClient ?client ; fin:forAccount ?account .
      ?account fin:frequencyLabel "Weekly" .
    }
  }
}

PREFIX fn: <http://financialdb.org/schema#>
SELECT ( AVG( ?loanAmount ) AS ?avgLoan ) WHERE {
  ?loan a fn:Loan ; fn:loanAmount ?loanAmount ; fn:status "A" ; fn:belongsToAccount ?acct .
  ?acct fn:frequencyLabel "After Transaction" .
}

PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT DISTINCT ?account ?accountId ?district ?districtName ?region WHERE {
  ?account a <http://financialdb.org/schema#Account> ; <http://financialdb.org/schema#accountId> ?accountId ; <http://financialdb.org/schema#createdOn> ?createdOn ; <http://financialdb.org/schema#belongsToDistrict> ?district .
  FILTER ( STRSTARTS( STR( ?createdOn ) , "1993" ) ) OPTIONAL {
    ?district rdfs:label ?districtName .
  }
  OPTIONAL {
    ?district <http://financialdb.org/schema#region> ?region .
  }
  ?txn <http://financialdb.org/schema#forAccount> ?account ; <http://financialdb.org/schema#transactionDate> ?tdate .
  ?disp <http://financialdb.org/schema#forAccount> ?account .
  ?card <http://financialdb.org/schema#linkedToDisposition> ?disp ; <http://financialdb.org/schema#issuedDate> ?issuedDate .
  FILTER ( xsd:date ( ?issuedDate ) > xsd:date ( ?tdate ) )
}
ORDER BY ?accountId

PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT DISTINCT ?account ?accountId ?frequencyLabel ?client ?clientLabel ?created WHERE {
  ?account a <http://financialdb.org/schema#Account> ; <http://financialdb.org/schema#accountId> ?accountId ; <http://financialdb.org/schema#createdOn> ?created .
  OPTIONAL {
    ?account <http://financialdb.org/schema#frequencyLabel> ?frequencyLabel .
  }
  ?disp <http://financialdb.org/schema#forAccount> ?account ; <http://financialdb.org/schema#forClient> ?client ; <http://financialdb.org/schema#dispositionType> "OWNER" .
  ?client <http://financialdb.org/schema#livesInDistrict> ?district .
  ?district <http://financialdb.org/schema#region> ?region .
  FILTER ( ?region = "east Bohemia" ) .
  FILTER ( ?created >= "1995-01-01" ^^ xsd:date && ?created <= "2000-12-31" ^^ xsd:date ) OPTIONAL {
    ?client rdfs:label ?clientLabel .
  }
}
ORDER BY ?accountId
